export interface PrayerTimes {
  Fajr: string;
  Sunrise: string;
  Dhuhr: string;
  Asr: string;
  Maghrib: string;
  Isha: string;
  [key: string]: string;
}

export interface HijriDate {
  date: string;
  format: string;
  day: string;
  weekday: { en: string; ar: string };
  month: { number: number; en: string; ar: string };
  year: string;
  designation: { abbreviated: string; expanded: string };
}

export interface PlaceResult {
  title: string;
  uri: string;
  snippet?: string;
  rating?: number;
  userRatingCount?: number;
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  text: string;
  timestamp: number;
}

export interface DailyVerse {
  arabic: string;
  translation: string;
  reference: string;
  reflection: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { DailyVerse, PlaceResult } from "../types";

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

export const generateDailyVerse = async (): Promise<DailyVerse | null> => {
  if (!apiKey) return null;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: "Generate a beautiful, inspiring Quranic verse or authentic Hadith for today. Include the Arabic text, English translation, reference, and a short 1-sentence spiritual reflection.",
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            arabic: { type: Type.STRING },
            translation: { type: Type.STRING },
            reference: { type: Type.STRING },
            reflection: { type: Type.STRING },
          },
          required: ["arabic", "translation", "reference", "reflection"],
        },
      },
    });

    const text = response.text;
    if (text) {
      return JSON.parse(text) as DailyVerse;
    }
  } catch (error) {
    console.error("Error generating verse:", error);
  }
  return null;
};

export const findMosques = async (lat: number, lng: number): Promise<{ text: string, places: PlaceResult[] }> => {
  if (!apiKey) return { text: "API Key missing", places: [] };

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: "Find the 5 best rated mosques or islamic centers nearby. Provide a brief summary of them.",
      config: {
        tools: [{ googleMaps: {} }],
        toolConfig: {
          retrievalConfig: {
            latLng: {
              latitude: lat,
              longitude: lng
            }
          }
        }
      },
    });

    const text = response.text || "No mosques found.";
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];

    // Extract map data
    const places: PlaceResult[] = [];
    chunks.forEach((chunk: any) => {
      if (chunk.web?.uri && chunk.web?.title) {
         // Fallback for web chunks if map chunks aren't distinct
         places.push({
             title: chunk.web.title,
             uri: chunk.web.uri
         });
      }
      // Specific maps grounding structure usually looks like this in recent versions, 
      // but the library output can vary. We check specifically for web entities that look like map results
      // or if the specialized maps chunk exists (schema varies, we will use a generic extraction strategy).
      // Based on documentation: groundingChunks.maps.uri
    });

    // Better extraction based on Gemini documentation for Maps
    // The chunks might contain `maps` property.
    /*
      structure: 
      [
        { maps: { title: "Masjid Al-Noor", uri: "https://maps.google..." } }
      ]
    */

    const mapPlaces = chunks
      .filter((c: any) => c.maps)
      .map((c: any) => ({
        title: c.maps.title,
        uri: c.maps.uri,
        snippet: c.maps.placeAnswerSources?.reviewSnippets?.[0]?.snippet
      }));

    return { text, places: mapPlaces.length > 0 ? mapPlaces : places };

  } catch (error) {
    console.error("Error finding mosques:", error);
    return { text: "Sorry, I couldn't search for mosques at this time.", places: [] };
  }
};

export const chatWithAi = async (message: string, history: { role: string, parts: { text: string }[] }[]): Promise<string> => {
  if (!apiKey) return "API Key missing.";

  try {
    const chat = ai.chats.create({
      model: 'gemini-3-flash-preview',
      history: history,
      config: {
        systemInstruction: "You are Noor, a knowledgeable, polite, and empathetic Islamic AI companion. You help users with questions about Islam, Duas, history, and spiritual advice. You avoid giving fatwas on controversial legal matters, instead suggesting they consult a local scholar for specific rulings. Keep answers concise, warm, and spiritually uplifting."
      }
    });

    const result = await chat.sendMessage({ message });
    return result.text || "I apologize, I couldn't generate a response.";
  } catch (error) {
    console.error("Chat error:", error);
    return "Sorry, something went wrong. Please try again later.";
  }
}

import { PrayerTimes, HijriDate } from "../types";

export const getPrayerTimes = async (lat: number, lng: number): Promise<{ timings: PrayerTimes, date: HijriDate } | null> => {
  try {
    const date = new Date();
    // Using Aladhan API
    const response = await fetch(`https://api.aladhan.com/v1/timings/${date.getDate()}-${date.getMonth() + 1}-${date.getFullYear()}?latitude=${lat}&longitude=${lng}&method=2`); // Method 2 is ISNA, usually a safe default or can be configured.
    const data = await response.json();

    if (data.code === 200 && data.data) {
      return {
        timings: data.data.timings,
        date: data.data.date.hijri
      };
    }
  } catch (error) {
    console.error("Error fetching prayer times:", error);
  }
  return null;
};

