import React, { useEffect, useState } from 'react';
import { PrayerTimes } from '../types';
import { Clock, Sun, Sunset, Moon, Sunrise } from 'lucide-react';

interface PrayerCardProps {
  timings: PrayerTimes | null;
  loading: boolean;
}

const PrayerCard: React.FC<PrayerCardProps> = ({ timings, loading }) => {
  const [nextPrayer, setNextPrayer] = useState<string>('');
  const [timeRemaining, setTimeRemaining] = useState<string>('');

  useEffect(() => {
    if (!timings) return;

    const prayers = ['Fajr', 'Dhuhr', 'Asr', 'Maghrib', 'Isha'];

    const updateNextPrayer = () => {
      const now = new Date();
      let upcoming = null;
      let upcomingName = '';

      for (const p of prayers) {
        const [hours, minutes] = timings[p].split(':').map(Number);
        const pTime = new Date();
        pTime.setHours(hours, minutes, 0, 0);

        if (pTime > now) {
          upcoming = pTime;
          upcomingName = p;
          break;
        }
      }

      if (!upcoming) {
        // Next is Fajr tomorrow
        const [hours, minutes] = timings['Fajr'].split(':').map(Number);
        upcoming = new Date();
        upcoming.setDate(upcoming.getDate() + 1);
        upcoming.setHours(hours, minutes, 0, 0);
        upcomingName = 'Fajr';
      }

      setNextPrayer(upcomingName);

      const diff = upcoming.getTime() - now.getTime();
      const diffHrs = Math.floor((diff % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60));
      const diffMins = Math.floor((diff % (1000 * 60 * 60)) / (1000 * 60));
      const diffSecs = Math.floor((diff % (1000 * 60)) / 1000); // Optional seconds

      setTimeRemaining(`- ${diffHrs}h ${diffMins}m`);
    };

    updateNextPrayer();
    const interval = setInterval(updateNextPrayer, 60000);
    return () => clearInterval(interval);
  }, [timings]);

  if (loading) {
    return (
      <div className="w-full h-64 bg-slate-100 animate-pulse rounded-3xl mb-6"></div>
    );
  }

  if (!timings) return null;

  const getIcon = (name: string) => {
    switch (name) {
      case 'Fajr': return <Sunrise className="w-5 h-5" />;
      case 'Dhuhr': return <Sun className="w-5 h-5" />;
      case 'Asr': return <Sun className="w-5 h-5 opacity-70" />;
      case 'Maghrib': return <Sunset className="w-5 h-5" />;
      case 'Isha': return <Moon className="w-5 h-5" />;
      default: return <Clock className="w-5 h-5" />;
    }
  };

  const prayers = [
    { name: 'Fajr', time: timings.Fajr },
    { name: 'Sunrise', time: timings.Sunrise, isPrayer: false },
    { name: 'Dhuhr', time: timings.Dhuhr },
    { name: 'Asr', time: timings.Asr },
    { name: 'Maghrib', time: timings.Maghrib },
    { name: 'Isha', time: timings.Isha },
  ];

  return (
    <div className="w-full bg-gradient-to-br from-emerald-600 to-teal-800 rounded-3xl p-6 text-white shadow-xl relative overflow-hidden mb-6">
      {/* Background decoration */}
      <div className="absolute top-0 right-0 w-64 h-64 bg-white opacity-5 rounded-full -mr-20 -mt-20 blur-3xl"></div>

      <div className="relative z-10 text-center mb-8">
        <p className="text-emerald-100 text-sm font-medium tracking-wide uppercase opacity-80">Next Prayer</p>
        <h2 className="text-4xl font-bold mt-1 mb-1">{nextPrayer}</h2>
        <p className="text-emerald-50 text-lg font-light tracking-wider">{timeRemaining}</p>
      </div>

      <div className="grid grid-cols-3 gap-3 relative z-10">
        {prayers.map((p) => {
          const isNext = p.name === nextPrayer;
          if (!p.isPrayer && p.name === 'Sunrise') return null; // Hide sunrise from grid to save space, or keep slightly different

          return (
            <div key={p.name} className={`flex flex-col items-center justify-center p-3 rounded-2xl transition-all ${isNext ? 'bg-white/20 backdrop-blur-md ring-1 ring-white/30' : 'bg-white/5'}`}>
              <div className={`mb-1 ${isNext ? 'text-white' : 'text-emerald-200'}`}>
                {getIcon(p.name)}
              </div>
              <span className="text-xs text-emerald-100 font-medium">{p.name}</span>
              <span className="text-sm font-bold">{p.time.split(' ')[0]}</span>
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default PrayerCard;

import React, { useEffect, useState } from 'react';
import { generateDailyVerse } from '../services/geminiService';
import { DailyVerse } from '../types';
import { Share2, Quote, Loader2 } from 'lucide-react';

const DailyVerseCard: React.FC = () => {
  const [verse, setVerse] = useState<DailyVerse | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Check session storage first to avoid API spam on reload
    const cached = sessionStorage.getItem('dailyVerse');
    if (cached) {
      setVerse(JSON.parse(cached));
      setLoading(false);
      return;
    }

    const fetchVerse = async () => {
      const data = await generateDailyVerse();
      if (data) {
        setVerse(data);
        sessionStorage.setItem('dailyVerse', JSON.stringify(data));
      }
      setLoading(false);
    };

    fetchVerse();
  }, []);

  if (loading) return (
    <div className="bg-white rounded-2xl p-6 shadow-sm border border-slate-100 flex justify-center items-center h-48">
        <Loader2 className="w-6 h-6 text-emerald-500 animate-spin" />
    </div>
  );

  if (!verse) return null;

  return (
    <div className="bg-white rounded-2xl p-6 shadow-sm border border-slate-100 relative group">
        <div className="absolute top-4 left-4 text-emerald-100">
            <Quote size={40} className="fill-current" />
        </div>

        <div className="relative z-10">
            <h3 className="text-xs font-bold text-emerald-600 uppercase tracking-wider mb-4 flex items-center gap-2">
                <span className="w-2 h-2 rounded-full bg-emerald-500"></span>
                Daily Inspiration
            </h3>

            <p className="font-arabic text-2xl text-slate-800 text-right leading-loose mb-4" dir="rtl">
                {verse.arabic}
            </p>

            <p className="text-slate-600 italic mb-3 leading-relaxed">
                "{verse.translation}"
            </p>

            <div className="flex justify-between items-end mt-4 pt-4 border-t border-slate-50">
                <div>
                    <p className="text-sm font-bold text-slate-800">{verse.reference}</p>
                    <p className="text-xs text-slate-500 mt-1 max-w-[250px]">{verse.reflection}</p>
                </div>

                <button 
                  onClick={() => navigator.clipboard.writeText(`${verse.translation} - ${verse.reference}`)}
                  className="p-2 text-slate-400 hover:text-emerald-600 hover:bg-emerald-50 rounded-full transition-colors"
                >
                    <Share2 size={18} />
                </button>
            </div>
        </div>
    </div>
  );
};

export default DailyVerseCard;

import React, { useState, useRef, useEffect } from 'react';
import { chatWithAi } from '../services/geminiService';
import { ChatMessage } from '../types';
import { Send, User, Sparkles } from 'lucide-react';

const ChatInterface: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      id: '1',
      role: 'model',
      text: 'As-salamu alaykum! I am Noor, your AI companion. How can I help you with your spiritual journey today?',
      timestamp: Date.now()
    }
  ]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || loading) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: input,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setLoading(true);

    const history = messages.map(m => ({
        role: m.role,
        parts: [{ text: m.text }]
    }));

    const responseText = await chatWithAi(userMsg.text, history);

    const aiMsg: ChatMessage = {
      id: (Date.now() + 1).toString(),
      role: 'model',
      text: responseText,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, aiMsg]);
    setLoading(false);
  };

  return (
    <div className="flex flex-col h-[calc(100vh-140px)] md:h-[600px] bg-slate-50 rounded-3xl border border-slate-200 overflow-hidden shadow-inner">
      <div className="flex-1 overflow-y-auto p-4 space-y-4">
        {messages.map((msg) => (
          <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`flex max-w-[85%] md:max-w-[75%] gap-2 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
              <div className={`w-8 h-8 rounded-full flex items-center justify-center flex-shrink-0 ${msg.role === 'user' ? 'bg-slate-200' : 'bg-emerald-100'}`}>
                {msg.role === 'user' ? <User size={16} className="text-slate-600" /> : <Sparkles size={16} className="text-emerald-600" />}
              </div>

              <div className={`p-3 rounded-2xl text-sm leading-relaxed ${
                msg.role === 'user' 
                  ? 'bg-emerald-600 text-white rounded-tr-none' 
                  : 'bg-white text-slate-800 shadow-sm border border-slate-100 rounded-tl-none'
              }`}>
                {msg.text}
              </div>
            </div>
          </div>
        ))}
        {loading && (
           <div className="flex justify-start">
             <div className="flex max-w-[85%] gap-2">
               <div className="w-8 h-8 rounded-full bg-emerald-100 flex items-center justify-center flex-shrink-0">
                 <Sparkles size={16} className="text-emerald-600 animate-pulse" />
               </div>
               <div className="bg-white p-3 rounded-2xl rounded-tl-none shadow-sm border border-slate-100">
                 <div className="flex gap-1">
                   <span className="w-2 h-2 bg-emerald-400 rounded-full animate-bounce"></span>
                   <span className="w-2 h-2 bg-emerald-400 rounded-full animate-bounce delay-100"></span>
                   <span className="w-2 h-2 bg-emerald-400 rounded-full animate-bounce delay-200"></span>
                 </div>
               </div>
             </div>
           </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      <div className="p-4 bg-white border-t border-slate-100">
        <div className="flex gap-2">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="Ask Noor about Islam, Duas, etc..."
            className="flex-1 bg-slate-50 border border-slate-200 rounded-full px-4 py-3 focus:outline-none focus:ring-2 focus:ring-emerald-500/20 focus:border-emerald-500 transition-all text-sm"
          />
          <button 
            onClick={handleSend}
            disabled={loading || !input.trim()}
            className="w-12 h-12 bg-emerald-600 hover:bg-emerald-700 disabled:opacity-50 disabled:cursor-not-allowed text-white rounded-full flex items-center justify-center transition-all shadow-md active:scale-95"
          >
            <Send size={20} className={loading ? 'opacity-0' : 'ml-0.5'} />
            {loading && <div className="absolute inset-0 flex items-center justify-center"><div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div></div>}
          </button>
        </div>
      </div>
    </div>
  );
};

export default ChatInterface;

import React, { useState } from 'react';
import { findMosques } from '../services/geminiService';
import { PlaceResult } from '../types';
import { MapPin, Navigation, Star, ExternalLink } from 'lucide-react';

interface MosqueFinderProps {
  location: { lat: number; lng: number } | null;
}

const MosqueFinder: React.FC<MosqueFinderProps> = ({ location }) => {
  const [places, setPlaces] = useState<PlaceResult[]>([]);
  const [text, setText] = useState<string>('');
  const [loading, setLoading] = useState(false);
  const [searched, setSearched] = useState(false);

  const handleSearch = async () => {
    if (!location) {
      alert("Please enable location services to find mosques nearby.");
      return;
    }
    setLoading(true);
    const result = await findMosques(location.lat, location.lng);
    setPlaces(result.places);
    setText(result.text);
    setLoading(false);
    setSearched(true);
  };

  return (
    <div className="space-y-6 pb-20">
      <div className="bg-emerald-50 rounded-3xl p-6 text-center border border-emerald-100">
        <div className="w-16 h-16 bg-white rounded-full flex items-center justify-center mx-auto mb-4 shadow-sm text-emerald-600">
          <MapPin size={32} />
        </div>
        <h2 className="text-xl font-bold text-slate-800 mb-2">Find Nearby Mosques</h2>
        <p className="text-slate-600 mb-6 text-sm max-w-xs mx-auto">Locate the nearest Masjids and Islamic Centers for prayer and community.</p>

        <button
          onClick={handleSearch}
          disabled={loading || !location}
          className="bg-emerald-600 hover:bg-emerald-700 text-white font-medium py-3 px-8 rounded-full shadow-lg shadow-emerald-600/20 active:scale-95 transition-all flex items-center gap-2 mx-auto disabled:opacity-50 disabled:cursor-not-allowed"
        >
          {loading ? (
             <>Searching...</>
          ) : (
             <><Navigation size={18} /> Search Nearby</>
          )}
        </button>
      </div>

      {searched && (
        <div className="space-y-4 animate-fade-in-up">
           <div className="px-2">
             <p className="text-sm text-slate-500 mb-2 font-medium uppercase tracking-wider">Results from Google Maps</p>
             {/* Gemini Text Summary if available */}
             {text && !places.length && (
                 <div className="bg-white p-4 rounded-2xl text-slate-700 text-sm leading-relaxed shadow-sm border border-slate-100">
                     {text}
                 </div>
             )}
           </div>

           <div className="grid gap-4">
             {places.map((place, idx) => (
               <a 
                 key={idx} 
                 href={place.uri} 
                 target="_blank" 
                 rel="noopener noreferrer"
                 className="block bg-white p-4 rounded-2xl shadow-sm border border-slate-100 hover:border-emerald-200 hover:shadow-md transition-all group"
               >
                 <div className="flex justify-between items-start">
                   <div>
                     <h3 className="font-bold text-slate-800 group-hover:text-emerald-700 transition-colors mb-1">{place.title}</h3>
                     {place.snippet && (
                         <p className="text-xs text-slate-500 line-clamp-2 mb-2">{place.snippet}</p>
                     )}
                     <div className="flex items-center gap-1 text-xs text-amber-500 font-medium">
                       <Star size={12} fill="currentColor" />
                       <span>Highly Rated</span>
                     </div>
                   </div>
                   <div className="w-8 h-8 bg-slate-50 rounded-full flex items-center justify-center text-slate-400 group-hover:bg-emerald-50 group-hover:text-emerald-600 transition-colors">
                     <ExternalLink size={16} />
                   </div>
                 </div>
               </a>
             ))}
             {places.length === 0 && !loading && (
               <div className="text-center py-8 text-slate-400 text-sm">
                 No mosques found nearby or location unavailable.
               </div>
             )}
           </div>
        </div>
      )}
    </div>
  );
};

export default MosqueFinder;

import React, { useState, useEffect } from 'react';
import Navigation from './components/Navigation';
import PrayerCard from './components/PrayerCard';
import ChatInterface from './components/ChatInterface';
import MosqueFinder from './components/MosqueFinder';
import DailyVerseCard from './components/DailyVerseCard';
import { getPrayerTimes } from './services/prayerService';
import { PrayerTimes, HijriDate } from './types';
import { Moon, Settings, MapPin, Loader } from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('home');
  const [location, setLocation] = useState<{ lat: number; lng: number } | null>(null);
  const [prayerData, setPrayerData] = useState<{ timings: PrayerTimes, date: HijriDate } | null>(null);
