import React, { useState, useEffect } from 'react';
import { RotateCcw, Settings, Check, Volume2, VolumeX, Smartphone } from 'lucide-react';

interface TasbihCounterProps {
  onBack: () => void;
}

const TasbihCounter: React.FC<TasbihCounterProps> = ({ onBack }) => {
  const [count, setCount] = useState(0);
  const [target, setTarget] = useState<number>(33);
  const [loops, setLoops] = useState(0);
  const [vibrationEnabled, setVibrationEnabled] = useState(true);

  useEffect(() => {
    const savedCount = localStorage.getItem('tasbih_count');
    const savedLoops = localStorage.getItem('tasbih_loops');
    const savedTarget = localStorage.getItem('tasbih_target');

    if (savedCount) setCount(parseInt(savedCount));
    if (savedLoops) setLoops(parseInt(savedLoops));
    if (savedTarget) setTarget(parseInt(savedTarget));
  }, []);

  useEffect(() => {
    localStorage.setItem('tasbih_count', count.toString());
    localStorage.setItem('tasbih_loops', loops.toString());
    localStorage.setItem('tasbih_target', target.toString());
  }, [count, loops, target]);

  const handleTap = () => {
    if (vibrationEnabled && navigator.vibrate) {
      navigator.vibrate(15); // Short tick
    }

    const nextCount = count + 1;

    if (target !== 0 && nextCount > target) {
      // Loop complete
      if (vibrationEnabled && navigator.vibrate) {
        navigator.vibrate([50, 50, 50]); // Distinct pattern for completion
      }
      setCount(1);
      setLoops(l => l + 1);
    } else {
      setCount(nextCount);
    }
  };

  const handleReset = () => {
    if (confirm("Reset current counter?")) {
      setCount(0);
      setLoops(0);
      if (vibrationEnabled && navigator.vibrate) navigator.vibrate(50);
    }
  };

  const toggleTarget = () => {
    const targets = [33, 99, 100, 0]; // 0 is infinity
    const currentIndex = targets.indexOf(target);
    const nextTarget = targets[(currentIndex + 1) % targets.length];
    setTarget(nextTarget);
  };

  const progress = target === 0 ? 100 : (count / target) * 100;

  return (
    <div className="flex flex-col h-full bg-slate-50 animate-fade-in relative overflow-hidden">
      {/* Header */}
      <div className="flex items-center justify-between p-6 z-10">
        <button 
          onClick={onBack} 
          className="w-10 h-10 bg-white rounded-full shadow-sm flex items-center justify-center text-slate-600 hover:text-emerald-600 transition-colors"
        >
          <RotateCcw size={20} />
        </button>
        <div className="flex flex-col items-center">
             <h1 className="text-xl font-bold text-slate-800">Tasbih</h1>
             <span className="text-xs text-slate-400 font-medium">Digital Dhikr</span>
        </div>
        <button 
          onClick={() => setVibrationEnabled(!vibrationEnabled)} 
          className={`w-10 h-10 rounded-full shadow-sm flex items-center justify-center transition-colors ${vibrationEnabled ? 'bg-emerald-50 text-emerald-600' : 'bg-white text-slate-400'}`}
        >
          {vibrationEnabled ? <Volume2 size={20} /> : <VolumeX size={20} />}
        </button>
      </div>

      <div className="flex-1 flex flex-col items-center justify-center px-6 pb-24 relative">

        {/* Info Display */}
        <div className="mb-8 text-center space-y-1">
            <p className="text-slate-400 text-xs font-medium uppercase tracking-wider">Total Loops: {loops}</p>
            <button 
                onClick={toggleTarget}
                className="bg-white border border-slate-200 px-3 py-1 rounded-full text-xs font-semibold text-slate-600 hover:border-emerald-500 transition-colors flex items-center gap-2 mx-auto"
            >
                Target: {target === 0 ? '∞' : target}
                <Settings size={12} />
            </button>
        </div>

        {/* Main Counter Button */}
        <button 
            onClick={handleTap}
            className="relative w-64 h-64 rounded-full bg-white shadow-[0_10px_40px_-10px_rgba(0,0,0,0.1)] flex items-center justify-center group active:scale-95 transition-all duration-100 touch-manipulation tap-highlight-transparent"
            style={{ WebkitTapHighlightColor: 'transparent' }}
        >
            {/* Progress Ring Background */}
            <svg className="absolute inset-0 w-full h-full -rotate-90 pointer-events-none" viewBox="0 0 100 100">
                <circle 
                    cx="50" cy="50" r="46" 
                    fill="none" 
                    stroke="#f1f5f9" 
                    strokeWidth="4" 
                />
                <circle 
                    cx="50" cy="50" r="46" 
                    fill="none" 
                    stroke="#10b981" 
                    strokeWidth="4" 
                    strokeDasharray="289" // 2 * pi * 46
                    strokeDashoffset={289 - (289 * progress) / 100}
                    strokeLinecap="round"
                    className="transition-all duration-300 ease-out"
                />
            </svg>

            {/* Inner Content */}
            <div className="flex flex-col items-center z-10">
                <span className="text-7xl font-bold text-slate-800 font-mono tracking-tighter tabular-nums select-none">
                    {count}
                </span>
                <span className="text-slate-400 text-sm font-medium mt-2">Tap to Count</span>
            </div>

            {/* Ripple effect container (could be enhanced with CSS animations) */}
            <div className="absolute inset-0 rounded-full border border-slate-100 group-active:border-emerald-200 transition-colors"></div>
        </button>

        {/* Reset Control */}
        <button 
            onClick={handleReset}
            className="mt-12 text-slate-400 hover:text-red-500 text-sm font-medium px-4 py-2 rounded-lg hover:bg-red-50 transition-colors flex items-center gap-2"
        >
            <RotateCcw size={14} />
            Reset Counter
        </button>
      </div>
    </div>
  );
};

export default TasbihCounter;

