import React, { useState, useEffect } from 'react';
import { RotateCcw, Compass, Navigation, ArrowUp, Smartphone } from 'lucide-react';

interface QiblaFinderProps {
  location: { lat: number; lng: number } | null;
  onBack: () => void;
}

const QiblaFinder: React.FC<QiblaFinderProps> = ({ location, onBack }) => {
  const [heading, setHeading] = useState<number>(0);
  const [qiblaBearing, setQiblaBearing] = useState<number>(0);
  const [permissionGranted, setPermissionGranted] = useState<boolean>(false);
  const [isIOS, setIsIOS] = useState<boolean>(false);
  const [isSupported, setIsSupported] = useState<boolean>(true);

  // Calculate Qibla Bearing (Great Circle)
  useEffect(() => {
    if (location) {
      const { lat, lng } = location;
      const KAABA_LAT = 21.422487;
      const KAABA_LNG = 39.826206;

      const toRad = (deg: number) => (deg * Math.PI) / 180;
      const toDeg = (rad: number) => (rad * 180) / Math.PI;

      const phi = toRad(lat);
      const lambda = toRad(lng);
      const phiK = toRad(KAABA_LAT);
      const lambdaK = toRad(KAABA_LNG);

      const y = Math.sin(lambdaK - lambda);
      const x = Math.cos(phi) * Math.tan(phiK) - Math.sin(phi) * Math.cos(lambdaK - lambda);

      let qibla = toDeg(Math.atan2(y, x));
      // Normalize to 0-360
      qibla = (qibla + 360) % 360;
      setQiblaBearing(qibla);
    }
  }, [location]);

  // Handle Compass Logic
  useEffect(() => {
    // Check if iOS (specific property on window or DeviceOrientationEvent)
    // @ts-ignore
    const isIOSCheck = typeof DeviceOrientationEvent !== 'undefined' && typeof DeviceOrientationEvent.requestPermission === 'function';
    setIsIOS(isIOSCheck);

    const handleOrientation = (e: DeviceOrientationEvent) => {
      let compass = 0;
      // @ts-ignore
      if (e.webkitCompassHeading) {
        // iOS
        // @ts-ignore
        compass = e.webkitCompassHeading;
      } else if (e.alpha !== null) {
        // Android / Standard (alpha is usually 0=North if absolute is supported, but often requires 'deviceorientationabsolute')
        // This is a basic fallback; 'deviceorientationabsolute' is preferred on Android for compass.
        compass = Math.abs(e.alpha - 360);
      }
      setHeading(compass);
    };

    if (!isIOSCheck) {
      if ('ondeviceorientationabsolute' in window) {
         (window as any).addEventListener('deviceorientationabsolute', handleOrientation as any, true);
      } else if ('ondeviceorientation' in window) {
         (window as any).addEventListener('deviceorientation', handleOrientation, true);
      } else {
         setIsSupported(false);
      }
      setPermissionGranted(true);
    }

    return () => {
      window.removeEventListener('deviceorientation', handleOrientation);
      if ('ondeviceorientationabsolute' in window) {
        (window as any).removeEventListener('deviceorientationabsolute', handleOrientation as any);
      }
    };
  }, []);

  const requestPermission = async () => {
    try {
      // @ts-ignore
      const response = await DeviceOrientationEvent.requestPermission();
      if (response === 'granted') {
        setPermissionGranted(true);
        // @ts-ignore
        window.addEventListener('deviceorientation', (e) => {
           // @ts-ignore
           setHeading(e.webkitCompassHeading || 0);
        }, true);
      } else {
        alert('Permission denied');
      }
    } catch (err) {
      console.error(err);
      alert('Error requesting permission');
    }
  };

  if (!location) {
    return (
      <div className="flex flex-col items-center justify-center h-full p-6 text-center">
        <div className="w-16 h-16 bg-amber-100 rounded-full flex items-center justify-center text-amber-600 mb-4">
          <Navigation size={32} />
        </div>
        <h2 className="text-xl font-bold text-slate-800">Location Needed</h2>
        <p className="text-slate-500 mt-2">Please enable location services to calculate the Qibla direction.</p>
        <button onClick={onBack} className="mt-6 text-emerald-600 font-medium hover:underline">Go Back</button>
      </div>
    );
  }

  // Calculate the rotation needed for the Qibla pointer relative to device North (top of phone)
  // The Compass Rose rotates by -heading to stay North.
  // The Qibla Pointer is placed at qiblaBearing on that Rose.
  const compassRotation = -heading;

  // Checking alignment (roughly within 5 degrees)
  const isAligned = Math.abs(heading - qiblaBearing) < 5 || Math.abs((heading - 360) - qiblaBearing) < 5;

  return (
    <div className="flex flex-col h-full bg-slate-50 animate-fade-in relative overflow-hidden">
      {/* Header */}
      <div className="flex items-center justify-between p-6 z-10">
        <button onClick={onBack} className="w-10 h-10 bg-white rounded-full shadow-sm flex items-center justify-center text-slate-600 hover:text-emerald-600 transition-colors">
          <RotateCcw size={20} />
        </button>
        <h1 className="text-xl font-bold text-slate-800">Qibla Finder</h1>
        <div className="w-10"></div>
      </div>

      <div className="flex-1 flex flex-col items-center justify-center px-6 relative pb-24">

        {/* Info Text */}
        <div className="text-center mb-10 z-10">
            <div className="inline-flex items-center gap-2 bg-white px-4 py-2 rounded-full shadow-sm border border-slate-100 mb-4">
               <Compass size={16} className="text-emerald-500" />
               <span className="text-sm font-semibold text-slate-700">{Math.round(qiblaBearing)}° North</span>
            </div>
            {isAligned ? (
              <h2 className="text-3xl font-bold text-emerald-600 animate-pulse">You are facing Qibla</h2>
            ) : (
              <h2 className="text-3xl font-bold text-slate-800">Rotate your phone</h2>
            )}
        </div>

        {/* Compass Visualization */}
        <div className="relative w-72 h-72 md:w-80 md:h-80 mb-8 flex items-center justify-center z-0">

            {/* Permission Button for iOS */}
            {isIOS && !permissionGranted && (
               <div className="absolute inset-0 z-50 flex items-center justify-center bg-white/80 backdrop-blur-sm rounded-full">
                  <button 
                    onClick={requestPermission}
                    className="bg-emerald-600 text-white px-6 py-3 rounded-full font-bold shadow-lg active:scale-95 transition-transform"
                  >
                    Enable Compass
                  </button>
               </div>
            )}

            {!isSupported && !isIOS && (
               <div className="absolute inset-0 z-50 flex flex-col items-center justify-center bg-white/90 backdrop-blur-sm rounded-full p-6 text-center">
                  <Smartphone size={32} className="text-slate-400 mb-2" />
                  <p className="text-sm text-slate-600 font-medium">Compass not supported on this device/browser.</p>
                  <p className="text-xs text-slate-400 mt-1">Qibla is at {Math.round(qiblaBearing)}°.</p>
               </div>
            )}

            {/* Static Indicator (Phone Top) */}
            <div className="absolute -top-6 left-1/2 -translate-x-1/2 text-slate-300">
               <ArrowUp size={24} />
            </div>

            {/* Rotating Compass Rose */}
            <div 
              className="w-full h-full rounded-full border-4 border-slate-200 bg-white shadow-2xl relative transition-transform duration-300 ease-out"
              style={{ transform: `rotate(${compassRotation}deg)` }}
            >
               {/* North Marker */}
               <div className="absolute top-2 left-1/2 -translate-x-1/2 flex flex-col items-center">
                  <span className="text-red-500 font-bold text-lg">N</span>
                  <div className="w-1 h-2 bg-red-500 rounded-full"></div>
               </div>

               {/* East */}
               <div className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-400 text-xs font-bold">E</div>
               {/* South */}
               <div className="absolute bottom-4 left-1/2 -translate-x-1/2 text-slate-400 text-xs font-bold">S</div>
               {/* West */}
               <div className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 text-xs font-bold">W</div>

               {/* Center Pivot */}
               <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-4 h-4 bg-slate-800 rounded-full z-20 border-2 border-slate-100"></div>

               {/* Kaaba/Qibla Pointer */}
               {/* This pointer sits on the rose at the correct degree */}
               <div 
                 className="absolute top-1/2 left-1/2 w-1 h-1/2 origin-bottom z-10"
                 style={{ transform: `translate(-50%, -100%) rotate(${qiblaBearing}deg)` }}
               >
                  <div className="absolute top-4 left-1/2 -translate-x-1/2 flex flex-col items-center">
                     {/* Kaaba Icon representation */}
                     <div className={`w-8 h-8 bg-black rounded-md border border-amber-400 flex items-center justify-center shadow-lg ${isAligned ? 'ring-4 ring-emerald-400/50' : ''}`}>
