import React, { useState, useRef, useEffect } from 'react';
import { chatWithAi } from '../services/geminiService';
import { ChatMessage } from '../types';
import { Send, User, Sparkles } from 'lucide-react';

const ChatInterface: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      id: '1',
      role: 'model',
      text: 'As-salamu alaykum! I am Noor, your AI companion. How can I help you with your spiritual journey today?',
      timestamp: Date.now()
    }
  ]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || loading) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: input,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setLoading(true);

    const history = messages.map(m => ({
        role: m.role,
        parts: [{ text: m.text }]
    }));

    const responseText = await chatWithAi(userMsg.text, history);

    const aiMsg: ChatMessage = {
      id: (Date.now() + 1).toString(),
      role: 'model',
      text: responseText,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, aiMsg]);
    setLoading(false);
  };

  return (
    <div className="flex flex-col h-[calc(100vh-140px)] md:h-[600px] bg-slate-50 dark:bg-slate-900 rounded-3xl border border-slate-200 dark:border-slate-800 overflow-hidden shadow-inner transition-colors duration-300">
      <div className="flex-1 overflow-y-auto p-4 space-y-4">
        {messages.map((msg) => (
          <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`flex max-w-[85%] md:max-w-[75%] gap-2 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
              <div className={`w-8 h-8 rounded-full flex items-center justify-center flex-shrink-0 ${msg.role === 'user' ? 'bg-slate-200 dark:bg-slate-700' : 'bg-emerald-100 dark:bg-emerald-900/30'}`}>
                {msg.role === 'user' ? <User size={16} className="text-slate-600 dark:text-slate-300" /> : <Sparkles size={16} className="text-emerald-600 dark:text-emerald-400" />}
              </div>

              <div className={`p-3 rounded-2xl text-sm leading-relaxed ${
                msg.role === 'user' 
                  ? 'bg-emerald-600 text-white rounded-tr-none' 
                  : 'bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-200 shadow-sm border border-slate-100 dark:border-slate-700 rounded-tl-none'
              }`}>
                {msg.text}
              </div>
            </div>
          </div>
        ))}
        {loading && (
           <div className="flex justify-start">
             <div className="flex max-w-[85%] gap-2">
               <div className="w-8 h-8 rounded-full bg-emerald-100 dark:bg-emerald-900/30 flex items-center justify-center flex-shrink-0">
                 <Sparkles size={16} className="text-emerald-600 dark:text-emerald-400 animate-pulse" />
               </div>
               <div className="bg-white dark:bg-slate-800 p-3 rounded-2xl rounded-tl-none shadow-sm border border-slate-100 dark:border-slate-700">
                 <div className="flex gap-1">
                   <span className="w-2 h-2 bg-emerald-400 rounded-full animate-bounce"></span>
                   <span className="w-2 h-2 bg-emerald-400 rounded-full animate-bounce delay-100"></span>
                   <span className="w-2 h-2 bg-emerald-400 rounded-full animate-bounce delay-200"></span>
                 </div>
               </div>
             </div>
           </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      <div className="p-4 bg-white dark:bg-slate-900 border-t border-slate-100 dark:border-slate-800 transition-colors duration-300">
        <div className="flex gap-2">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="Ask Noor about Islam, Duas, etc..."
            className="flex-1 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-full px-4 py-3 focus:outline-none focus:ring-2 focus:ring-emerald-500/20 focus:border-emerald-500 dark:text-slate-100 transition-all text-sm placeholder:text-slate-400 dark:placeholder:text-slate-500"
          />
          <button 
            onClick={handleSend}
            disabled={loading || !input.trim()}
            className="w-12 h-12 bg-emerald-600 hover:bg-emerald-700 disabled:opacity-50 disabled:cursor-not-allowed text-white rounded-full flex items-center justify-center transition-all shadow-md active:scale-95"
          >
            <Send size={20} className={loading ? 'opacity-0' : 'ml-0.5'} />
            {loading && <div className="absolute inset-0 flex items-center justify-center"><div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div></div>}
          </button>
        </div>
      </div>
    </div>
  );
};

export default ChatInterface;

import React, { useEffect, useState } from 'react';
import { generateDailyVerse } from '../services/geminiService';
import { DailyVerse } from '../types';
import { Share2, Quote, Loader2 } from 'lucide-react';

const DailyVerseCard: React.FC = () => {
  const [verse, setVerse] = useState<DailyVerse | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Check session storage first to avoid API spam on reload
    const cached = sessionStorage.getItem('dailyVerse');
    if (cached) {
      setVerse(JSON.parse(cached));
      setLoading(false);
      return;
    }

    const fetchVerse = async () => {
      const data = await generateDailyVerse();
      if (data) {
        setVerse(data);
        sessionStorage.setItem('dailyVerse', JSON.stringify(data));
      }
      setLoading(false);
    };

    fetchVerse();
  }, []);

  if (loading) return (
    <div className="bg-white dark:bg-slate-900 rounded-2xl p-6 shadow-sm border border-slate-100 dark:border-slate-800 flex justify-center items-center h-48 transition-colors duration-300">
        <Loader2 className="w-6 h-6 text-emerald-500 animate-spin" />
    </div>
  );

  if (!verse) return null;

  return (
    <div className="bg-white dark:bg-slate-900 rounded-2xl p-6 shadow-sm border border-slate-100 dark:border-slate-800 relative group transition-colors duration-300">
        <div className="absolute top-4 left-4 text-emerald-100 dark:text-emerald-900/30">
            <Quote size={40} className="fill-current" />
        </div>

        <div className="relative z-10">
            <h3 className="text-xs font-bold text-emerald-600 dark:text-emerald-400 uppercase tracking-wider mb-4 flex items-center gap-2">
                <span className="w-2 h-2 rounded-full bg-emerald-500"></span>
                Daily Inspiration
            </h3>

            <p className="font-arabic text-2xl text-slate-800 dark:text-slate-100 text-right leading-loose mb-4" dir="rtl">
                {verse.arabic}
            </p>

            <p className="text-slate-600 dark:text-slate-300 italic mb-3 leading-relaxed">
                "{verse.translation}"
            </p>

            <div className="flex justify-between items-end mt-4 pt-4 border-t border-slate-50 dark:border-slate-800">
                <div>
                    <p className="text-sm font-bold text-slate-800 dark:text-slate-200">{verse.reference}</p>
                    <p className="text-xs text-slate-500 dark:text-slate-500 mt-1 max-w-[250px]">{verse.reflection}</p>
                </div>

                <button 
                  onClick={() => navigator.clipboard.writeText(`${verse.translation} - ${verse.reference}`)}
                  className="p-2 text-slate-400 dark:text-slate-500 hover:text-emerald-600 dark:hover:text-emerald-400 hover:bg-emerald-50 dark:hover:bg-emerald-900/20 rounded-full transition-colors"
                >
                    <Share2 size={18} />
                </button>
            </div>
        </div>
    </div>
  );
};

