import React, { useState } from 'react';
import { findMosques } from '../services/geminiService';
import { PlaceResult } from '../types';
import { MapPin, Navigation, Star, ExternalLink } from 'lucide-react';

interface MosqueFinderProps {
  location: { lat: number; lng: number } | null;
}

const MosqueFinder: React.FC<MosqueFinderProps> = ({ location }) => {
  const [places, setPlaces] = useState<PlaceResult[]>([]);
  const [text, setText] = useState<string>('');
  const [loading, setLoading] = useState(false);
  const [searched, setSearched] = useState(false);

  const handleSearch = async () => {
    if (!location) {
      alert("Please enable location services to find mosques nearby.");
      return;
    }
    setLoading(true);
    const result = await findMosques(location.lat, location.lng);
    setPlaces(result.places);
    setText(result.text);
    setLoading(false);
    setSearched(true);
  };

  return (
    <div className="space-y-6 pb-20">
      <div className="bg-emerald-50 dark:bg-emerald-900/20 rounded-3xl p-6 text-center border border-emerald-100 dark:border-emerald-900/30 transition-colors duration-300">
        <div className="w-16 h-16 bg-white dark:bg-slate-800 rounded-full flex items-center justify-center mx-auto mb-4 shadow-sm text-emerald-600 dark:text-emerald-400 transition-colors">
          <MapPin size={32} />
        </div>
        <h2 className="text-xl font-bold text-slate-800 dark:text-slate-100 mb-2">Find Nearby Mosques</h2>
        <p className="text-slate-600 dark:text-slate-400 mb-6 text-sm max-w-xs mx-auto">Locate the nearest Masjids and Islamic Centers for prayer and community.</p>

        <button
          onClick={handleSearch}
          disabled={loading || !location}
          className="bg-emerald-600 hover:bg-emerald-700 text-white font-medium py-3 px-8 rounded-full shadow-lg shadow-emerald-600/20 active:scale-95 transition-all flex items-center gap-2 mx-auto disabled:opacity-50 disabled:cursor-not-allowed"
        >
          {loading ? (
             <>Searching...</>
          ) : (
             <><Navigation size={18} /> Search Nearby</>
          )}
        </button>
      </div>

      {searched && (
        <div className="space-y-4 animate-fade-in-up">
           <div className="px-2">
             <p className="text-sm text-slate-500 dark:text-slate-400 mb-2 font-medium uppercase tracking-wider">Results from Google Maps</p>
             {/* Gemini Text Summary if available */}
             {text && !places.length && (
                 <div className="bg-white dark:bg-slate-900 p-4 rounded-2xl text-slate-700 dark:text-slate-300 text-sm leading-relaxed shadow-sm border border-slate-100 dark:border-slate-800">
                     {text}
                 </div>
             )}
           </div>

           <div className="grid gap-4">
             {places.map((place, idx) => (
               <a 
                 key={idx} 
                 href={place.uri} 
                 target="_blank" 
                 rel="noopener noreferrer"
