                     )}
                     <div className="flex items-center gap-1 text-xs text-amber-500 font-medium">
                       <Star size={12} fill="currentColor" />
                       <span>Highly Rated</span>
                     </div>
                   </div>
                   <div className="w-8 h-8 bg-slate-50 dark:bg-slate-800 rounded-full flex items-center justify-center text-slate-400 dark:text-slate-500 group-hover:bg-emerald-50 dark:group-hover:bg-emerald-900/30 group-hover:text-emerald-600 dark:group-hover:text-emerald-400 transition-colors">
                     <ExternalLink size={16} />
