                 </div>
               </a>
             ))}
             {places.length === 0 && !loading && (
               <div className="text-center py-8 text-slate-400 dark:text-slate-500 text-sm">
                 No mosques found nearby or location unavailable.
               </div>
             )}
           </div>
        </div>
      )}
    </div>
  );
};

