import React, { useState, useEffect } from 'react';
import { RotateCcw, Settings, Check, Volume2, VolumeX, Smartphone } from 'lucide-react';

interface TasbihCounterProps {
  onBack: () => void;
}

const TasbihCounter: React.FC<TasbihCounterProps> = ({ onBack }) => {
  const [count, setCount] = useState(0);
  const [target, setTarget] = useState<number>(33);
  const [loops, setLoops] = useState(0);
  const [vibrationEnabled, setVibrationEnabled] = useState(true);

  useEffect(() => {
    const savedCount = localStorage.getItem('tasbih_count');
    const savedLoops = localStorage.getItem('tasbih_loops');
    const savedTarget = localStorage.getItem('tasbih_target');

    if (savedCount) setCount(parseInt(savedCount));
    if (savedLoops) setLoops(parseInt(savedLoops));
    if (savedTarget) setTarget(parseInt(savedTarget));
  }, []);

  useEffect(() => {
    localStorage.setItem('tasbih_count', count.toString());
    localStorage.setItem('tasbih_loops', loops.toString());
    localStorage.setItem('tasbih_target', target.toString());
  }, [count, loops, target]);

  const handleTap = () => {
    if (vibrationEnabled && navigator.vibrate) {
      navigator.vibrate(15); // Short tick
    }

    const nextCount = count + 1;

    if (target !== 0 && nextCount > target) {
      // Loop complete
      if (vibrationEnabled && navigator.vibrate) {
        navigator.vibrate([50, 50, 50]); // Distinct pattern for completion
      }
      setCount(1);
      setLoops(l => l + 1);
    } else {
      setCount(nextCount);
    }
  };

  const handleReset = () => {
    if (confirm("Reset current counter?")) {
      setCount(0);
      setLoops(0);
      if (vibrationEnabled && navigator.vibrate) navigator.vibrate(50);
    }
  };

  const toggleTarget = () => {
    const targets = [33, 99, 100, 0]; // 0 is infinity
    const currentIndex = targets.indexOf(target);
    const nextTarget = targets[(currentIndex + 1) % targets.length];
    setTarget(nextTarget);
  };

  const progress = target === 0 ? 100 : (count / target) * 100;

  return (
    <div className="flex flex-col h-full bg-slate-50 dark:bg-slate-950 animate-fade-in relative overflow-hidden transition-colors duration-300">
      {/* Header */}
      <div className="flex items-center justify-between p-6 z-10">
        <button 
          onClick={onBack} 
          className="w-10 h-10 bg-white dark:bg-slate-900 rounded-full shadow-sm flex items-center justify-center text-slate-600 dark:text-slate-300 hover:text-emerald-600 dark:hover:text-emerald-400 transition-colors"
        >
          <RotateCcw size={20} />
        </button>
        <div className="flex flex-col items-center">
             <h1 className="text-xl font-bold text-slate-800 dark:text-slate-100">Tasbih</h1>
             <span className="text-xs text-slate-400 dark:text-slate-500 font-medium">Digital Dhikr</span>
        </div>
        <button 
          onClick={() => setVibrationEnabled(!vibrationEnabled)} 
          className={`w-10 h-10 rounded-full shadow-sm flex items-center justify-center transition-colors ${vibrationEnabled ? 'bg-emerald-50 dark:bg-emerald-900/20 text-emerald-600 dark:text-emerald-400' : 'bg-white dark:bg-slate-900 text-slate-400 dark:text-slate-500'}`}
        >
          {vibrationEnabled ? <Volume2 size={20} /> : <VolumeX size={20} />}
        </button>
      </div>

      <div className="flex-1 flex flex-col items-center justify-center px-6 pb-24 relative">

        {/* Info Display */}
        <div className="mb-8 text-center space-y-1">
            <p className="text-slate-400 dark:text-slate-500 text-xs font-medium uppercase tracking-wider">Total Loops: {loops}</p>
            <button 
                onClick={toggleTarget}
                className="bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 px-3 py-1 rounded-full text-xs font-semibold text-slate-600 dark:text-slate-300 hover:border-emerald-500 dark:hover:border-emerald-500 transition-colors flex items-center gap-2 mx-auto"
            >
                Target: {target === 0 ? '∞' : target}
                <Settings size={12} />
            </button>
        </div>

        {/* Main Counter Button */}
        <button 
            onClick={handleTap}
            className="relative w-64 h-64 rounded-full bg-white dark:bg-slate-900 shadow-[0_10px_40px_-10px_rgba(0,0,0,0.1)] dark:shadow-[0_10px_40px_-10px_rgba(0,0,0,0.5)] flex items-center justify-center group active:scale-95 transition-all duration-100 touch-manipulation tap-highlight-transparent"
            style={{ WebkitTapHighlightColor: 'transparent' }}
        >
            {/* Progress Ring Background */}
            <svg className="absolute inset-0 w-full h-full -rotate-90 pointer-events-none" viewBox="0 0 100 100">
                <circle 
                    cx="50" cy="50" r="46" 
                    fill="none" 
                    className="stroke-slate-100 dark:stroke-slate-800 transition-colors duration-300"
                    strokeWidth="4" 
                />
                <circle 
                    cx="50" cy="50" r="46" 
                    fill="none" 
                    stroke="#10b981" 
                    strokeWidth="4" 
                    strokeDasharray="289" // 2 * pi * 46
                    strokeDashoffset={289 - (289 * progress) / 100}
                    strokeLinecap="round"
                    className="transition-all duration-300 ease-out"
                />
            </svg>

            {/* Inner Content */}
            <div className="flex flex-col items-center z-10">
                <span className="text-7xl font-bold text-slate-800 dark:text-slate-100 font-mono tracking-tighter tabular-nums select-none">
                    {count}
                </span>
                <span className="text-slate-400 dark:text-slate-500 text-sm font-medium mt-2">Tap to Count</span>
            </div>

            {/* Ripple effect container */}
            <div className="absolute inset-0 rounded-full border border-slate-100 dark:border-slate-800 group-active:border-emerald-200 dark:group-active:border-emerald-800 transition-colors"></div>
        </button>

        {/* Reset Control */}
        <button 
            onClick={handleReset}
            className="mt-12 text-slate-400 hover:text-red-500 dark:text-slate-500 dark:hover:text-red-400 text-sm font-medium px-4 py-2 rounded-lg hover:bg-red-50 dark:hover:bg-red-900/20 transition-colors flex items-center gap-2"
        >
            <RotateCcw size={14} />
            Reset Counter
        </button>
      </div>
    </div>
  );
};

export default TasbihCounter;

import React, { useState, useEffect } from 'react';
import { RotateCcw, Compass, Navigation, ArrowUp, Smartphone } from 'lucide-react';

interface QiblaFinderProps {
  location: { lat: number; lng: number } | null;
  onBack: () => void;
}

const QiblaFinder: React.FC<QiblaFinderProps> = ({ location, onBack }) => {
  const [heading, setHeading] = useState<number>(0);
  const [qiblaBearing, setQiblaBearing] = useState<number>(0);
  const [permissionGranted, setPermissionGranted] = useState<boolean>(false);
  const [isIOS, setIsIOS] = useState<boolean>(false);
  const [isSupported, setIsSupported] = useState<boolean>(true);

  // Calculate Qibla Bearing (Great Circle)
  useEffect(() => {
    if (location) {
      const { lat, lng } = location;
      const KAABA_LAT = 21.422487;
      const KAABA_LNG = 39.826206;

      const toRad = (deg: number) => (deg * Math.PI) / 180;
      const toDeg = (rad: number) => (rad * 180) / Math.PI;

      const phi = toRad(lat);
      const lambda = toRad(lng);
      const phiK = toRad(KAABA_LAT);
      const lambdaK = toRad(KAABA_LNG);

      const y = Math.sin(lambdaK - lambda);
      const x = Math.cos(phi) * Math.tan(phiK) - Math.sin(phi) * Math.cos(lambdaK - lambda);

      let qibla = toDeg(Math.atan2(y, x));
      // Normalize to 0-360
      qibla = (qibla + 360) % 360;
      setQiblaBearing(qibla);
    }
  }, [location]);

  // Handle Compass Logic
  useEffect(() => {
    // Check if iOS (specific property on window or DeviceOrientationEvent)
    // @ts-ignore
    const isIOSCheck = typeof DeviceOrientationEvent !== 'undefined' && typeof DeviceOrientationEvent.requestPermission === 'function';
    setIsIOS(isIOSCheck);

    const handleOrientation = (e: DeviceOrientationEvent) => {
      let compass = 0;
      // @ts-ignore
      if (e.webkitCompassHeading) {
        // iOS
        // @ts-ignore
        compass = e.webkitCompassHeading;
      } else if (e.alpha !== null) {
        // Android / Standard (alpha is usually 0=North if absolute is supported, but often requires 'deviceorientationabsolute')
        // This is a basic fallback; 'deviceorientationabsolute' is preferred on Android for compass.
        compass = Math.abs(e.alpha - 360);
      }
      setHeading(compass);
    };

    if (!isIOSCheck) {
      if ('ondeviceorientationabsolute' in window) {
         (window as any).addEventListener('deviceorientationabsolute', handleOrientation as any, true);
      } else if ('ondeviceorientation' in window) {
         (window as any).addEventListener('deviceorientation', handleOrientation, true);
      } else {
         setIsSupported(false);
      }
      setPermissionGranted(true);
    }

    return () => {
      window.removeEventListener('deviceorientation', handleOrientation);
      if ('ondeviceorientationabsolute' in window) {
        (window as any).removeEventListener('deviceorientationabsolute', handleOrientation as any);
      }
    };
  }, []);

  const requestPermission = async () => {
    try {
      // @ts-ignore
      const response = await DeviceOrientationEvent.requestPermission();
      if (response === 'granted') {
        setPermissionGranted(true);
        // @ts-ignore
        window.addEventListener('deviceorientation', (e) => {
           // @ts-ignore
           setHeading(e.webkitCompassHeading || 0);
        }, true);
      } else {
        alert('Permission denied');
      }
    } catch (err) {
      console.error(err);
      alert('Error requesting permission');
    }
  };

  if (!location) {
    return (
      <div className="flex flex-col items-center justify-center h-full p-6 text-center">
        <div className="w-16 h-16 bg-amber-100 dark:bg-amber-900/30 rounded-full flex items-center justify-center text-amber-600 dark:text-amber-400 mb-4">
          <Navigation size={32} />
        </div>
        <h2 className="text-xl font-bold text-slate-800 dark:text-slate-100">Location Needed</h2>
        <p className="text-slate-500 dark:text-slate-400 mt-2">Please enable location services to calculate the Qibla direction.</p>
        <button onClick={onBack} className="mt-6 text-emerald-600 dark:text-emerald-400 font-medium hover:underline">Go Back</button>
      </div>
    );
  }

  // Calculate the rotation needed for the Qibla pointer relative to device North (top of phone)
  // The Compass Rose rotates by -heading to stay North.
  // The Qibla Pointer is placed at qiblaBearing on that Rose.
  const compassRotation = -heading;

  // Checking alignment (roughly within 5 degrees)
  const isAligned = Math.abs(heading - qiblaBearing) < 5 || Math.abs((heading - 360) - qiblaBearing) < 5;

  return (
    <div className="flex flex-col h-full bg-slate-50 dark:bg-slate-950 animate-fade-in relative overflow-hidden transition-colors duration-300">
      {/* Header */}
      <div className="flex items-center justify-between p-6 z-10">
        <button onClick={onBack} className="w-10 h-10 bg-white dark:bg-slate-900 rounded-full shadow-sm flex items-center justify-center text-slate-600 dark:text-slate-300 hover:text-emerald-600 dark:hover:text-emerald-400 transition-colors">
          <RotateCcw size={20} />
        </button>
        <h1 className="text-xl font-bold text-slate-800 dark:text-slate-100">Qibla Finder</h1>
        <div className="w-10"></div>
      </div>

      <div className="flex-1 flex flex-col items-center justify-center px-6 relative pb-24">

        {/* Info Text */}
        <div className="text-center mb-10 z-10">
            <div className="inline-flex items-center gap-2 bg-white dark:bg-slate-900 px-4 py-2 rounded-full shadow-sm border border-slate-100 dark:border-slate-800 mb-4">
               <Compass size={16} className="text-emerald-500" />
               <span className="text-sm font-semibold text-slate-700 dark:text-slate-200">{Math.round(qiblaBearing)}° North</span>
            </div>
            {isAligned ? (
              <h2 className="text-3xl font-bold text-emerald-600 dark:text-emerald-400 animate-pulse">You are facing Qibla</h2>
            ) : (
              <h2 className="text-3xl font-bold text-slate-800 dark:text-slate-100">Rotate your phone</h2>
            )}
        </div>

        {/* Compass Visualization */}
        <div className="relative w-72 h-72 md:w-80 md:h-80 mb-8 flex items-center justify-center z-0">

            {/* Permission Button for iOS */}
            {isIOS && !permissionGranted && (
               <div className="absolute inset-0 z-50 flex items-center justify-center bg-white/80 dark:bg-slate-900/80 backdrop-blur-sm rounded-full">
                  <button 
                    onClick={requestPermission}
                    className="bg-emerald-600 text-white px-6 py-3 rounded-full font-bold shadow-lg active:scale-95 transition-transform"
                  >
                    Enable Compass
                  </button>
               </div>
            )}

            {!isSupported && !isIOS && (
               <div className="absolute inset-0 z-50 flex flex-col items-center justify-center bg-white/90 dark:bg-slate-900/90 backdrop-blur-sm rounded-full p-6 text-center">
                  <Smartphone size={32} className="text-slate-400 mb-2" />
                  <p className="text-sm text-slate-600 dark:text-slate-300 font-medium">Compass not supported on this device/browser.</p>
                  <p className="text-xs text-slate-400 mt-1">Qibla is at {Math.round(qiblaBearing)}°.</p>
               </div>
            )}

            {/* Static Indicator (Phone Top) */}
            <div className="absolute -top-6 left-1/2 -translate-x-1/2 text-slate-300 dark:text-slate-600">
               <ArrowUp size={24} />
            </div>

            {/* Rotating Compass Rose */}
            <div 
              className="w-full h-full rounded-full border-4 border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 shadow-2xl relative transition-all duration-300 ease-out"
              style={{ transform: `rotate(${compassRotation}deg)` }}
            >
               {/* North Marker */}
               <div className="absolute top-2 left-1/2 -translate-x-1/2 flex flex-col items-center">
                  <span className="text-red-500 font-bold text-lg">N</span>
                  <div className="w-1 h-2 bg-red-500 rounded-full"></div>
               </div>

               {/* East */}
               <div className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-400 dark:text-slate-500 text-xs font-bold">E</div>
               {/* South */}
               <div className="absolute bottom-4 left-1/2 -translate-x-1/2 text-slate-400 dark:text-slate-500 text-xs font-bold">S</div>
               {/* West */}
               <div className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 dark:text-slate-500 text-xs font-bold">W</div>

               {/* Center Pivot */}
               <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-4 h-4 bg-slate-800 dark:bg-slate-300 rounded-full z-20 border-2 border-slate-100 dark:border-slate-600"></div>

               {/* Kaaba/Qibla Pointer */}
               {/* This pointer sits on the rose at the correct degree */}
               <div 
                 className="absolute top-1/2 left-1/2 w-1 h-1/2 origin-bottom z-10"
                 style={{ transform: `translate(-50%, -100%) rotate(${qiblaBearing}deg)` }}
               >
                  <div className="absolute top-4 left-1/2 -translate-x-1/2 flex flex-col items-center">
                     {/* Kaaba Icon representation */}
                     <div className={`w-8 h-8 bg-black rounded-md border border-amber-400 flex items-center justify-center shadow-lg ${isAligned ? 'ring-4 ring-emerald-400/50' : ''}`}>
                        <div className="w-full h-[1px] bg-amber-400 mt-[-4px]"></div>
                     </div>
                     <div className={`w-1 h-16 mt-2 rounded-full ${isAligned ? 'bg-emerald-500' : 'bg-slate-300 dark:bg-slate-600'}`}></div>
                  </div>
               </div>
            </div>
        </div>
      </div>
    </div>
  );
};

export default QiblaFinder;

import React, { useState, useEffect, useRef } from 'react';
import { Search, ChevronLeft, ArrowLeft, Loader2, AlertCircle } from 'lucide-react';

interface Surah {
  number: number;
  name: string;
  englishName: string;
  englishNameTranslation: string;
  numberOfAyahs: number;
  revelationType: string;
}

interface Ayah {
  number: number;
  text: string;
  numberInSurah: number;
}

const QuranReader: React.FC = () => {
  const [surahs, setSurahs] = useState<Surah[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [searchTerm, setSearchTerm] = useState('');
  const [activeSurah, setActiveSurah] = useState<Surah | null>(null);
  const [ayahs, setAyahs] = useState<{arabic: string, translation: string, number: number}[]>([]);
  const [loadingSurah, setLoadingSurah] = useState(false);
  const topRef = useRef<HTMLDivElement>(null);

  // Fetch Surah List
  useEffect(() => {
    const fetchSurahs = async () => {
      try {
        const cached = localStorage.getItem('quran_surahs');
        if (cached) {
            setSurahs(JSON.parse(cached));
            setLoading(false);
            return;
        }

        const res = await fetch('https://api.alquran.cloud/v1/surah');
        const data = await res.json();
        if (data.code === 200) {
          setSurahs(data.data);
          localStorage.setItem('quran_surahs', JSON.stringify(data.data));
        } else {
          setError('Failed to load Surahs');
        }
      } catch (err) {
        setError('Network error. Please check connection.');
      } finally {
        setLoading(false);
      }
    };
    fetchSurahs();
  }, []);

  // Fetch Specific Surah
  const selectSurah = async (surah: Surah) => {
    setActiveSurah(surah);
    setLoadingSurah(true);
    setAyahs([]);

    try {
       // Fetch Arabic and English
       const res = await fetch(`https://api.alquran.cloud/v1/surah/${surah.number}/editions/quran-uthmani,en.sahih`);
       const data = await res.json();

       if (data.code === 200 && data.data.length >= 2) {
           const arabicAyahs = data.data[0].ayahs;
           const englishAyahs = data.data[1].ayahs;

           const combined = arabicAyahs.map((ayah: any, index: number) => ({
               number: ayah.numberInSurah,
               arabic: ayah.text,
               translation: englishAyahs[index]?.text || ''
           }));

           setAyahs(combined);
       }
    } catch (err) {
        console.error(err);
        setError('Failed to load verses.');
    } finally {
        setLoadingSurah(false);
        // Scroll to top when loading
        if(topRef.current) topRef.current.scrollTop = 0;
    }
  };

  const handleBack = () => {
    setActiveSurah(null);
    setAyahs([]);
  };

  const filteredSurahs = surahs.filter(s => 
    s.englishName.toLowerCase().includes(searchTerm.toLowerCase()) || 
    s.englishNameTranslation.toLowerCase().includes(searchTerm.toLowerCase()) ||
    s.number.toString().includes(searchTerm)
  );

  // Render List
  if (!activeSurah) {
     return (
        <div className="h-full flex flex-col animate-fade-in">
           <div className="px-6 pt-2 pb-4 bg-white dark:bg-slate-950 sticky top-0 z-10">
              <h1 className="text-2xl font-bold text-slate-800 dark:text-slate-100 mb-4">The Noble Quran</h1>
              <div className="relative">
                 <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                 <input 
                   type="text" 
                   placeholder="Search Surah by name or number..." 
                   className="w-full bg-slate-100 dark:bg-slate-900 border-none rounded-xl py-3 pl-10 pr-4 text-slate-800 dark:text-slate-100 placeholder:text-slate-400 focus:ring-2 focus:ring-emerald-500/50 outline-none transition-all"
                   value={searchTerm}
                   onChange={(e) => setSearchTerm(e.target.value)}
                 />
              </div>
           </div>

           <div className="flex-1 overflow-y-auto px-6 pb-24">
              {loading ? (
                  <div className="flex justify-center pt-10"><Loader2 className="animate-spin text-emerald-600" /></div>
              ) : error ? (
                  <div className="flex flex-col items-center justify-center pt-10 text-center">
                    <AlertCircle className="text-red-500 mb-2" />
                    <p className="text-slate-600 dark:text-slate-400">{error}</p>
                    <button onClick={() => window.location.reload()} className="mt-4 text-emerald-600 font-medium">Retry</button>
                  </div>
              ) : (
                  <div className="space-y-3">
                      {filteredSurahs.map(surah => (
                          <button 
                            key={surah.number}
                            onClick={() => selectSurah(surah)}
                            className="w-full bg-white dark:bg-slate-900 p-4 rounded-2xl border border-slate-100 dark:border-slate-800 hover:border-emerald-200 dark:hover:border-emerald-800 hover:shadow-sm transition-all flex items-center gap-4 text-left group"
                          >
                             <div className="w-10 h-10 bg-slate-50 dark:bg-slate-800 rounded-lg flex items-center justify-center font-bold text-slate-400 dark:text-slate-500 group-hover:text-emerald-600 dark:group-hover:text-emerald-400 group-hover:bg-emerald-50 dark:group-hover:bg-emerald-900/20 transition-colors">
                                 {surah.number}
                             </div>
                             <div className="flex-1">
                                 <h3 className="font-bold text-slate-800 dark:text-slate-100">{surah.englishName}</h3>
                                 <p className="text-xs text-slate-500 dark:text-slate-400">{surah.englishNameTranslation} • {surah.numberOfAyahs} Verses</p>
                             </div>
                             <div className="text-right">
                                 <span className="font-arabic text-xl text-slate-700 dark:text-slate-200">{surah.name.replace('سُورَةُ ', '')}</span>
                             </div>
                          </button>
                      ))}
                      {filteredSurahs.length === 0 && (
                          <p className="text-center text-slate-400 py-10">No Surahs found.</p>
                      )}
                  </div>
              )}
           </div>
        </div>
     );
  }

  // Render Detail
  return (
      <div className="h-full flex flex-col animate-fade-in bg-white dark:bg-slate-950">
          {/* Header */}
          <div className="px-4 py-4 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between sticky top-0 bg-white/95 dark:bg-slate-950/95 backdrop-blur-sm z-20 transition-colors">
              <button 
                onClick={handleBack}
                className="w-10 h-10 rounded-full hover:bg-slate-100 dark:hover:bg-slate-900 flex items-center justify-center text-slate-600 dark:text-slate-300 transition-colors"
              >
                  <ArrowLeft size={22} />
              </button>
              <div className="text-center">
                  <h2 className="font-bold text-slate-800 dark:text-slate-100">{activeSurah.englishName}</h2>
                  <p className="text-xs text-slate-500 dark:text-slate-400">{activeSurah.englishNameTranslation}</p>
              </div>
              <div className="w-10"></div> {/* Spacer for alignment */}
          </div>

          <div ref={topRef} className="flex-1 overflow-y-auto pb-24 scroll-smooth">
               {/* Bismillah Header - Show for all except At-Tawbah (9) */}
               {activeSurah.number !== 9 && !loadingSurah && (
                   <div className="py-8 flex justify-center text-slate-800 dark:text-slate-100 opacity-80">
                       <p className="font-arabic text-3xl">بِسْمِ ٱللَّٰهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ</p>
                   </div>
               )}

               {loadingSurah ? (
                   <div className="flex flex-col items-center justify-center py-32 space-y-4">
                       <Loader2 className="animate-spin text-emerald-600" size={32} />
                       <p className="text-sm text-slate-400">Loading verses...</p>
