                                       {ayah.arabic} 
                                       <span className="inline-flex items-center justify-center w-8 h-8 mx-2 text-sm border border-emerald-500/50 rounded-full text-emerald-600 dark:text-emerald-400 font-sans number-symbol align-middle bg-white dark:bg-slate-800">
                                           {ayah.number}
                                       </span>
                                   </p>
                               </div>

                               {/* Translation */}
                               <div className="px-2">
                                   <p className="text-slate-600 dark:text-slate-300 leading-relaxed text-lg">
                                       {ayah.translation}
                                   </p>
                               </div>

                               {idx < ayahs.length - 1 && (
                                   <div className="my-8 border-b border-slate-100 dark:border-slate-800/60 w-1/2 mx-auto"></div>
                               )}
                           </div>
                       ))}
                   </div>
               )}
          </div>
      </div>
  );
};

export default QuranReader;

import React, { useState, useEffect } from 'react';
import Navigation from './components/Navigation';
import PrayerCard from './components/PrayerCard';
import ChatInterface from './components/ChatInterface';
import MosqueFinder from './components/MosqueFinder';
import DailyVerseCard from './components/DailyVerseCard';
import QiblaFinder from './components/QiblaFinder';
import TasbihCounter from './components/TasbihCounter';
import QuranReader from './components/QuranReader';
import { getPrayerTimes } from './services/prayerService';
import { PrayerTimes, HijriDate } from './types';
import { Moon, Settings, MapPin, Loader, Compass, Hand, Sun } from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('home');
  const [location, setLocation] = useState<{ lat: number; lng: number } | null>(null);
  const [prayerData, setPrayerData] = useState<{ timings: PrayerTimes, date: HijriDate } | null>(null);
  const [loadingPrayers, setLoadingPrayers] = useState(true);

  // Dark Mode State
  const [darkMode, setDarkMode] = useState(() => {
    if (typeof window !== 'undefined') {
      const saved = localStorage.getItem('darkMode');
      // Default to true if user prefers dark mode and no saved preference
      if (saved === null) {
          return window.matchMedia('(prefers-color-scheme: dark)').matches;
      }
      return saved === 'true';
    }
    return false;
  });

  // Apply Dark Mode Class
  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('darkMode', 'true');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('darkMode', 'false');
    }
  }, [darkMode]);

  useEffect(() => {
    // Attempt to get location
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        async (position) => {
          const { latitude, longitude } = position.coords;
          setLocation({ lat: latitude, lng: longitude });

          const data = await getPrayerTimes(latitude, longitude);
          setPrayerData(data);
          setLoadingPrayers(false);
        },
        async (error) => {
          console.warn("Location permission denied, defaulting to London", error);
          // Default to London
          const defLat = 51.5074;
          const defLng = -0.1278;
          setLocation({ lat: defLat, lng: defLng });
          const data = await getPrayerTimes(defLat, defLng);
          setPrayerData(data);
          setLoadingPrayers(false);
        }
      );
    } else {
       // Fallback logic
       setLoadingPrayers(false);
    }
  }, []);

  const renderHeader = () => (
    <header className="flex justify-between items-center mb-6">
      <div>
        <h1 className="text-2xl font-bold text-slate-800 dark:text-slate-100">Noor</h1>
        <p className="text-xs text-slate-500 dark:text-slate-400 font-medium">
          {prayerData ? `${prayerData.date.weekday.en}, ${prayerData.date.day} ${prayerData.date.month.en} ${prayerData.date.year}` : 'Islamic Companion'}
        </p>
      </div>
      <div className="flex gap-3 items-center">
        {location && (
          <div className="bg-emerald-50 dark:bg-emerald-900/30 text-emerald-600 dark:text-emerald-400 px-3 py-1.5 rounded-full text-xs font-semibold flex items-center gap-1 border border-transparent dark:border-emerald-900/50">
             <MapPin size={12} />
             {location.lat === 51.5074 ? 'London' : 'My Location'}
          </div>
        )}
        <button 
            onClick={() => setDarkMode(!darkMode)}
            className="w-8 h-8 rounded-full bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-300 flex items-center justify-center hover:bg-slate-200 dark:hover:bg-slate-700 transition-colors"
        >
            {darkMode ? <Sun size={16} /> : <Moon size={16} />}
        </button>
      </div>
    </header>
  );

  const renderContent = () => {
    switch (activeTab) {
      case 'home':
        return (
          <div className="space-y-6 pb-24 animate-fade-in">
            {renderHeader()}
            <PrayerCard timings={prayerData?.timings || null} loading={loadingPrayers} />
            <DailyVerseCard />

            <div className="grid grid-cols-2 gap-4">
               <button onClick={() => setActiveTab('tasbih')} className="bg-white dark:bg-slate-900 p-4 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-800 flex flex-col gap-2 hover:border-emerald-200 dark:hover:border-emerald-900 transition-all text-left group">
                  <div className="w-10 h-10 rounded-full bg-blue-50 dark:bg-blue-900/20 text-blue-500 dark:text-blue-400 flex items-center justify-center group-hover:bg-blue-100 dark:group-hover:bg-blue-900/30 transition-colors">
                     <Hand size={20} />
                  </div>
                  <span className="font-semibold text-slate-700 dark:text-slate-200">Tasbih Counter</span>
                  <span className="text-xs text-slate-400 dark:text-slate-500">Digital dhikr</span>
               </button>
               <button onClick={() => setActiveTab('qibla')} className="bg-white dark:bg-slate-900 p-4 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-800 flex flex-col gap-2 hover:border-emerald-200 dark:hover:border-emerald-900 transition-all text-left group">
                  <div className="w-10 h-10 rounded-full bg-purple-50 dark:bg-purple-900/20 text-purple-500 dark:text-purple-400 flex items-center justify-center group-hover:bg-purple-100 dark:group-hover:bg-purple-900/30 transition-colors">
                     <Compass size={20} />
                  </div>
                  <span className="font-semibold text-slate-700 dark:text-slate-200">Qibla Finder</span>
                  <span className="text-xs text-slate-400 dark:text-slate-500">Direction</span>
               </button>
            </div>
          </div>
        );
      case 'mosques':
        return (
          <div className="pt-6 animate-fade-in">
             <h1 className="text-2xl font-bold text-slate-800 dark:text-slate-100 mb-6 px-2">Mosques</h1>
             <MosqueFinder location={location} />
          </div>
        );
      case 'chat':
        return (
          <div className="pt-6 h-full flex flex-col animate-fade-in">
            <h1 className="text-2xl font-bold text-slate-800 dark:text-slate-100 mb-4 px-2">Ask Noor AI</h1>
            <ChatInterface />
          </div>
        );
      case 'qibla':
        return (
          <div className="h-full animate-fade-in">
             <QiblaFinder location={location} onBack={() => setActiveTab('home')} />
          </div>
        );
      case 'tasbih':
        return (
          <div className="h-full animate-fade-in">
             <TasbihCounter onBack={() => setActiveTab('home')} />
