        );
      case 'quran':
          return (
              <div className="h-full animate-fade-in">
                  <QuranReader />
              </div>
          )
      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 dark:bg-slate-950 relative transition-colors duration-300">
      <div className="max-w-md mx-auto min-h-screen bg-white dark:bg-slate-950 md:shadow-2xl md:border-x md:border-slate-100 dark:md:border-slate-800 relative overflow-hidden transition-colors duration-300">

        {/* Main Content Area */}
        <main className="p-6 min-h-screen pb-24">
          {renderContent()}
        </main>

        {activeTab !== 'qibla' && activeTab !== 'tasbih' && activeTab !== 'quran' && (
           <Navigation activeTab={activeTab} setActiveTab={setActiveTab} />
        )}

        {/* Show nav in Quran List view, but we can't easily detect list view from here. 
            So we'll just show nav always for 'quran', unless it conflicts with full screen readers. 
            The QuranReader handles its own sticky headers, so having the bottom nav is fine.
        */}
        {activeTab === 'quran' && (
           <Navigation activeTab={activeTab} setActiveTab={setActiveTab} />
        )}
      </div>

      {/* Desktop Helper */}
      <div className="hidden md:block fixed top-1/2 left-10 -translate-y-1/2 max-w-xs">
          <h2 className="text-3xl font-bold text-slate-800 dark:text-slate-100 mb-4">Noor App</h2>
          <p className="text-slate-600 dark:text-slate-400">Experience the mobile interface in the center of your screen. Built with React, Tailwind, and Gemini AI.</p>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { Search, ChevronLeft, ArrowLeft, Loader2, AlertCircle, BookOpen, Clock } from 'lucide-react';

interface Surah {
  number: number;
  name: string;
  englishName: string;
  englishNameTranslation: string;
  numberOfAyahs: number;
  revelationType: string;
}

interface Ayah {
  number: number;
  text: string;
  numberInSurah: number;
}

interface LastRead {
  number: number;
  name: string;
  englishName: string;
  timestamp: number;
}

const QuranReader: React.FC = () => {
  const [surahs, setSurahs] = useState<Surah[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [searchTerm, setSearchTerm] = useState('');
  const [activeSurah, setActiveSurah] = useState<Surah | null>(null);
  const [ayahs, setAyahs] = useState<{arabic: string, translation: string, number: number}[]>([]);
  const [loadingSurah, setLoadingSurah] = useState(false);
  const [lastRead, setLastRead] = useState<LastRead | null>(null);
  const topRef = useRef<HTMLDivElement>(null);

  // Fetch Surah List & Last Read
  useEffect(() => {
    const fetchSurahs = async () => {
      try {
        // Load Last Read
        const savedProgress = localStorage.getItem('quran_last_read');
        if (savedProgress) {
            setLastRead(JSON.parse(savedProgress));
        }

        const cached = localStorage.getItem('quran_surahs');
        if (cached) {
            setSurahs(JSON.parse(cached));
            setLoading(false);
            return;
        }

        const res = await fetch('https://api.alquran.cloud/v1/surah');
        const data = await res.json();
        if (data.code === 200) {
          setSurahs(data.data);
          localStorage.setItem('quran_surahs', JSON.stringify(data.data));
        } else {
          setError('Failed to load Surahs');
        }
      } catch (err) {
        setError('Network error. Please check connection.');
      } finally {
        setLoading(false);
      }
    };
    fetchSurahs();
  }, []);

  // Fetch Specific Surah
  const selectSurah = async (surah: Surah) => {
    setActiveSurah(surah);
    setLoadingSurah(true);
    setAyahs([]);

    // Save Progress
    const progress: LastRead = {
        number: surah.number,
        name: surah.name,
        englishName: surah.englishName,
        timestamp: Date.now()
    };
    setLastRead(progress);
    localStorage.setItem('quran_last_read', JSON.stringify(progress));

    try {
       // Fetch Arabic and English
       const res = await fetch(`https://api.alquran.cloud/v1/surah/${surah.number}/editions/quran-uthmani,en.sahih`);
       const data = await res.json();

       if (data.code === 200 && data.data.length >= 2) {
           const arabicAyahs = data.data[0].ayahs;
           const englishAyahs = data.data[1].ayahs;

           const combined = arabicAyahs.map((ayah: any, index: number) => ({
               number: ayah.numberInSurah,
               arabic: ayah.text,
               translation: englishAyahs[index]?.text || ''
           }));

           setAyahs(combined);
       }
    } catch (err) {
        console.error(err);
        setError('Failed to load verses.');
    } finally {
        setLoadingSurah(false);
        // Scroll to top when loading
        if(topRef.current) topRef.current.scrollTop = 0;
    }
  };

  const handleBack = () => {
    setActiveSurah(null);
    setAyahs([]);
  };

  const filteredSurahs = surahs.filter(s => 
    s.englishName.toLowerCase().includes(searchTerm.toLowerCase()) || 
    s.englishNameTranslation.toLowerCase().includes(searchTerm.toLowerCase()) ||
    s.number.toString().includes(searchTerm)
  );

  const continueReading = () => {
      if (lastRead) {
          const surah = surahs.find(s => s.number === lastRead.number);
          if (surah) selectSurah(surah);
      }
  };

  // Render List
  if (!activeSurah) {
     return (
        <div className="h-full flex flex-col animate-fade-in">
           <div className="px-6 pt-2 pb-4 bg-white dark:bg-slate-950 sticky top-0 z-10">
              <h1 className="text-2xl font-bold text-slate-800 dark:text-slate-100 mb-4">The Noble Quran</h1>
              <div className="relative">
                 <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                 <input 
                   type="text" 
                   placeholder="Search Surah by name or number..." 
                   className="w-full bg-slate-100 dark:bg-slate-900 border-none rounded-xl py-3 pl-10 pr-4 text-slate-800 dark:text-slate-100 placeholder:text-slate-400 focus:ring-2 focus:ring-emerald-500/50 outline-none transition-all"
                   value={searchTerm}
                   onChange={(e) => setSearchTerm(e.target.value)}
                 />
              </div>
           </div>

           <div className="flex-1 overflow-y-auto px-6 pb-24">
              {loading ? (
                  <div className="flex justify-center pt-10"><Loader2 className="animate-spin text-emerald-600" /></div>
              ) : error ? (
                  <div className="flex flex-col items-center justify-center pt-10 text-center">
                    <AlertCircle className="text-red-500 mb-2" />
                    <p className="text-slate-600 dark:text-slate-400">{error}</p>
                    <button onClick={() => window.location.reload()} className="mt-4 text-emerald-600 font-medium">Retry</button>
                  </div>
              ) : (
                  <div className="space-y-3">
                      {/* Last Read Card */}
                      {lastRead && !searchTerm && (
                          <div className="mb-6 animate-fade-in">
                              <h2 className="text-xs font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wider mb-3 px-1">Continue Reading</h2>
                              <button 
                                  onClick={continueReading}
                                  className="w-full bg-gradient-to-r from-emerald-600 to-teal-700 p-5 rounded-2xl text-white shadow-lg shadow-emerald-600/20 flex items-center justify-between group transform transition-all active:scale-[0.98]"
                              >
                                  <div className="flex items-center gap-4">
                                      <div className="w-12 h-12 bg-white/20 backdrop-blur-sm rounded-full flex items-center justify-center shadow-inner">
                                          <BookOpen size={22} className="text-white" />
                                      </div>
                                      <div className="text-left">
                                          <p className="text-emerald-100 text-xs font-medium mb-1 flex items-center gap-1">
                                            <Clock size={10} /> Last Read
                                          </p>
                                          <p className="font-bold text-xl">{lastRead.englishName}</p>
                                      </div>
                                  </div>
                                  <div className="font-arabic text-3xl opacity-80 text-emerald-100">{lastRead.name.replace('سُورَةُ ', '')}</div>
                              </button>
                          </div>
                      )}

                      {/* Surah List */}
                      {searchTerm && <h2 className="text-xs font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wider mb-3 px-1">Search Results</h2>}

                      {filteredSurahs.map(surah => (
                          <button 
                            key={surah.number}
                            onClick={() => selectSurah(surah)}
                            className="w-full bg-white dark:bg-slate-900 p-4 rounded-2xl border border-slate-100 dark:border-slate-800 hover:border-emerald-200 dark:hover:border-emerald-800 hover:shadow-sm transition-all flex items-center gap-4 text-left group"
                          >
                             <div className="w-10 h-10 bg-slate-50 dark:bg-slate-800 rounded-lg flex items-center justify-center font-bold text-slate-400 dark:text-slate-500 group-hover:text-emerald-600 dark:group-hover:text-emerald-400 group-hover:bg-emerald-50 dark:group-hover:bg-emerald-900/20 transition-colors">
                                 {surah.number}
                             </div>
                             <div className="flex-1">
                                 <h3 className="font-bold text-slate-800 dark:text-slate-100">{surah.englishName}</h3>
                                 <p className="text-xs text-slate-500 dark:text-slate-400">{surah.englishNameTranslation} • {surah.numberOfAyahs} Verses</p>
                             </div>
                             <div className="text-right">
                                 <span className="font-arabic text-xl text-slate-700 dark:text-slate-200">{surah.name.replace('سُورَةُ ', '')}</span>
                             </div>
                          </button>
                      ))}
                      {filteredSurahs.length === 0 && (
                          <p className="text-center text-slate-400 py-10">No Surahs found.</p>
                      )}
                  </div>
              )}
           </div>
        </div>
     );
  }

  // Render Detail
  return (
      <div className="h-full flex flex-col animate-fade-in bg-white dark:bg-slate-950">
          {/* Header */}
          <div className="px-4 py-4 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between sticky top-0 bg-white/95 dark:bg-slate-950/95 backdrop-blur-sm z-20 transition-colors">
              <button 
                onClick={handleBack}
                className="w-10 h-10 rounded-full hover:bg-slate-100 dark:hover:bg-slate-900 flex items-center justify-center text-slate-600 dark:text-slate-300 transition-colors"
              >
                  <ArrowLeft size={22} />
              </button>
              <div className="text-center">
                  <h2 className="font-bold text-slate-800 dark:text-slate-100">{activeSurah.englishName}</h2>
                  <p className="text-xs text-slate-500 dark:text-slate-400">{activeSurah.englishNameTranslation}</p>
              </div>
              <div className="w-10"></div> {/* Spacer for alignment */}
          </div>

          <div ref={topRef} className="flex-1 overflow-y-auto pb-24 scroll-smooth">
               {/* Bismillah Header - Show for all except At-Tawbah (9) */}
               {activeSurah.number !== 9 && !loadingSurah && (
                   <div className="py-8 flex justify-center text-slate-800 dark:text-slate-100 opacity-80">
                       <p className="font-arabic text-3xl">بِسْمِ ٱللَّٰهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ</p>
                   </div>
               )}

               {loadingSurah ? (
                   <div className="flex flex-col items-center justify-center py-32 space-y-4">
                       <Loader2 className="animate-spin text-emerald-600" size={32} />
                       <p className="text-sm text-slate-400">Loading verses...</p>
                   </div>
               ) : (
                   <div className="px-6 space-y-8 pb-10">
                       {ayahs.map((ayah, idx) => (
                           <div key={idx} className="scroll-mt-20">
                               {/* Arabic */}
                               <div className="w-full bg-slate-50 dark:bg-slate-900/40 p-6 rounded-2xl mb-4 border border-slate-100 dark:border-slate-800/50">
                                   <p className="text-right font-arabic text-3xl leading-[2.5] text-slate-800 dark:text-slate-100" dir="rtl">
                                       {ayah.arabic} 
                                       <span className="inline-flex items-center justify-center w-8 h-8 mx-2 text-sm border border-emerald-500/50 rounded-full text-emerald-600 dark:text-emerald-400 font-sans number-symbol align-middle bg-white dark:bg-slate-800">
                                           {ayah.number}
                                       </span>
                                   </p>
                               </div>

                               {/* Translation */}
                               <div className="px-2">
                                   <p className="text-slate-600 dark:text-slate-300 leading-relaxed text-lg">
                                       {ayah.translation}
                                   </p>
                               </div>

                               {idx < ayahs.length - 1 && (
                                   <div className="my-8 border-b border-slate-100 dark:border-slate-800/60 w-1/2 mx-auto"></div>
                               )}
                           </div>
                       ))}
                   </div>
               )}
          </div>
      </div>
  );
};

export default QuranReader;

