  const [reciters, setReciters] = useState<Reciter[]>([]);
  const [activeReciter, setActiveReciter] = useState<Reciter>({ 
      identifier: 'ar.alafasy', 
      name: 'Mishary Rashid Alafasy', 
      englishName: 'Alafasy', 
      format: 'audio',
      language: 'ar'
  });
  const [showReciterList, setShowReciterList] = useState(false);
  const [audioUrls, setAudioUrls] = useState<string[]>([]);
  const [currentAudioIndex, setCurrentAudioIndex] = useState(-1);
  const [isPlaying, setIsPlaying] = useState(false);
  const [loadingAudio, setLoadingAudio] = useState(false);

  const topRef = useRef<HTMLDivElement>(null);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  // Fetch Surah List & Last Read & Reciters
  useEffect(() => {
    const fetchData = async () => {
      try {
        // Load Last Read
        const savedProgress = localStorage.getItem('quran_last_read');
        if (savedProgress) {
            setLastRead(JSON.parse(savedProgress));
        }

        // Load Reciters
        const cachedReciters = localStorage.getItem('quran_reciters');
        if (cachedReciters) {
            setReciters(JSON.parse(cachedReciters));
        } else {
            // Fetch Reciters
            fetch('https://api.alquran.cloud/v1/edition?format=audio&language=ar&type=versebyverse')
                .then(res => res.json())
                .then(data => {
                    if (data.code === 200) {
                        setReciters(data.data);
                        localStorage.setItem('quran_reciters', JSON.stringify(data.data));
                    }
                })
                .catch(console.error);
        }

        const cached = localStorage.getItem('quran_surahs');
        if (cached) {
            setSurahs(JSON.parse(cached));
            setLoading(false);
            return;
        }

        const res = await fetch('https://api.alquran.cloud/v1/surah');
        const data = await res.json();
        if (data.code === 200) {
          setSurahs(data.data);
          localStorage.setItem('quran_surahs', JSON.stringify(data.data));
        } else {
          setError('Failed to load Surahs');
        }
      } catch (err) {
        setError('Network error. Please check connection.');
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, []);

  // Fetch Specific Surah
  const selectSurah = async (surah: Surah) => {
    setActiveSurah(surah);
    setLoadingSurah(true);
    setAyahs([]);
    resetAudio();

    // Save Progress
    const progress: LastRead = {
        number: surah.number,
        name: surah.name,
        englishName: surah.englishName,
        timestamp: Date.now()
    };
    setLastRead(progress);
    localStorage.setItem('quran_last_read', JSON.stringify(progress));

    try {
       // Fetch Arabic and English
       const res = await fetch(`https://api.alquran.cloud/v1/surah/${surah.number}/editions/quran-uthmani,en.sahih`);
       const data = await res.json();

       if (data.code === 200 && data.data.length >= 2) {
           const arabicAyahs = data.data[0].ayahs;
           const englishAyahs = data.data[1].ayahs;

           const combined = arabicAyahs.map((ayah: any, index: number) => ({
               number: ayah.numberInSurah,
               arabic: ayah.text,
               translation: englishAyahs[index]?.text || ''
           }));

           setAyahs(combined);
       }
    } catch (err) {
        console.error(err);
        setError('Failed to load verses.');
    } finally {
        setLoadingSurah(false);
        if(topRef.current) topRef.current.scrollTop = 0;
    }
  };

  const handleBack = () => {
    setActiveSurah(null);
    setAyahs([]);
    resetAudio();
  };

  // Audio Functions
  const resetAudio = () => {
      setIsPlaying(false);
      setCurrentAudioIndex(-1);
      setAudioUrls([]);
      if (audioRef.current) {
          audioRef.current.pause();
          audioRef.current.currentTime = 0;
      }
  };

  const togglePlay = async () => {
      if (loadingAudio) return;

      if (isPlaying) {
          audioRef.current?.pause();
          setIsPlaying(false);
      } else {
          if (audioUrls.length === 0 && activeSurah) {
              await loadAudioForSurah(activeSurah.number);
          }

          if (currentAudioIndex === -1) {
              setCurrentAudioIndex(0);
          } else {
              audioRef.current?.play();
          }
          setIsPlaying(true);
      }
  };

  const loadAudioForSurah = async (surahNumber: number) => {
      setLoadingAudio(true);
      try {
          const res = await fetch(`https://api.alquran.cloud/v1/surah/${surahNumber}/${activeReciter.identifier}`);
          const data = await res.json();
          if (data.code === 200) {
              const urls = data.data.ayahs.map((a: any) => a.audio);
              setAudioUrls(urls);
          }
      } catch (err) {
          console.error("Error loading audio", err);
          alert("Could not load audio for this reciter.");
      } finally {
          setLoadingAudio(false);
      }
  };

  const handleReciterChange = (reciter: Reciter) => {
      setActiveReciter(reciter);
      setShowReciterList(false);
      // Reset current audio to force reload with new reciter on next play
      resetAudio();
  };

  // Audio Player Effect
  useEffect(() => {
      const audio = audioRef.current;
      if (!audio) return;

      const playCurrentVerse = async () => {
          if (currentAudioIndex >= 0 && currentAudioIndex < audioUrls.length && isPlaying) {
              audio.src = audioUrls[currentAudioIndex];
              try {
                  await audio.play();
                  // Scroll to verse
                  document.getElementById(`ayah-${currentAudioIndex + 1}`)?.scrollIntoView({ behavior: 'smooth', block: 'center' });
              } catch (e) {
                  console.error("Play failed", e);
                  setIsPlaying(false);
              }
          }
      };

      playCurrentVerse();

      const handleEnded = () => {
          if (currentAudioIndex < audioUrls.length - 1) {
              setCurrentAudioIndex(prev => prev + 1);
          } else {
              setIsPlaying(false);
              setCurrentAudioIndex(0); // Reset to start
          }
      };

      audio.addEventListener('ended', handleEnded);
      return () => audio.removeEventListener('ended', handleEnded);
  }, [currentAudioIndex, audioUrls, isPlaying]);


  const filteredSurahs = surahs.filter(s => 
    s.englishName.toLowerCase().includes(searchTerm.toLowerCase()) || 
    s.englishNameTranslation.toLowerCase().includes(searchTerm.toLowerCase()) ||
    s.number.toString().includes(searchTerm)
  );

  const continueReading = () => {
      if (lastRead) {
          const surah = surahs.find(s => s.number === lastRead.number);
          if (surah) selectSurah(surah);
      }
  };

  // Render List
  if (!activeSurah) {
     return (
        <div className="h-full flex flex-col animate-fade-in relative">
           <div className="px-6 pt-2 pb-4 bg-white dark:bg-slate-950 sticky top-0 z-10">
              <h1 className="text-2xl font-bold text-slate-800 dark:text-slate-100 mb-4">The Noble Quran</h1>
              <div className="relative">
                 <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                 <input 
                   type="text" 
                   placeholder="Search Surah..." 
                   className="w-full bg-slate-100 dark:bg-slate-900 border-none rounded-xl py-3 pl-10 pr-4 text-slate-800 dark:text-slate-100 placeholder:text-slate-400 focus:ring-2 focus:ring-emerald-500/50 outline-none transition-all"
                   value={searchTerm}
                   onChange={(e) => setSearchTerm(e.target.value)}
                 />
              </div>
           </div>

           <div className="flex-1 overflow-y-auto px-6 pb-24">
              {loading ? (
                  <div className="flex justify-center pt-10"><Loader2 className="animate-spin text-emerald-600" /></div>
              ) : error ? (
                  <div className="flex flex-col items-center justify-center pt-10 text-center">
                    <AlertCircle className="text-red-500 mb-2" />
                    <p className="text-slate-600 dark:text-slate-400">{error}</p>
                    <button onClick={() => window.location.reload()} className="mt-4 text-emerald-600 font-medium">Retry</button>
                  </div>
              ) : (
                  <div className="space-y-3">
                      {/* Last Read Card */}
                      {lastRead && !searchTerm && (
                          <div className="mb-6 animate-fade-in">
                              <h2 className="text-xs font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wider mb-3 px-1">Continue Reading</h2>
                              <button 
                                  onClick={continueReading}
                                  className="w-full bg-gradient-to-r from-emerald-600 to-teal-700 p-5 rounded-2xl text-white shadow-lg shadow-emerald-600/20 flex items-center justify-between group transform transition-all active:scale-[0.98]"
                              >
                                  <div className="flex items-center gap-4">
                                      <div className="w-12 h-12 bg-white/20 backdrop-blur-sm rounded-full flex items-center justify-center shadow-inner">
                                          <BookOpen size={22} className="text-white" />
                                      </div>
                                      <div className="text-left">
                                          <p className="text-emerald-100 text-xs font-medium mb-1 flex items-center gap-1">
                                            <Clock size={10} /> Last Read
                                          </p>
                                          <p className="font-bold text-xl">{lastRead.englishName}</p>
                                      </div>
                                  </div>
                                  <div className="font-arabic text-3xl opacity-80 text-emerald-100">{lastRead.name.replace('سُورَةُ ', '')}</div>
                              </button>
                          </div>
                      )}

                      {/* Surah List */}
                      {searchTerm && <h2 className="text-xs font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wider mb-3 px-1">Search Results</h2>}

                      {filteredSurahs.map(surah => (
                          <button 
                            key={surah.number}
                            onClick={() => selectSurah(surah)}
                            className="w-full bg-white dark:bg-slate-900 p-4 rounded-2xl border border-slate-100 dark:border-slate-800 hover:border-emerald-200 dark:hover:border-emerald-800 hover:shadow-sm transition-all flex items-center gap-4 text-left group"
                          >
                             <div className="w-10 h-10 bg-slate-50 dark:bg-slate-800 rounded-lg flex items-center justify-center font-bold text-slate-400 dark:text-slate-500 group-hover:text-emerald-600 dark:group-hover:text-emerald-400 group-hover:bg-emerald-50 dark:group-hover:bg-emerald-900/20 transition-colors">
                                 {surah.number}
                             </div>
                             <div className="flex-1">
                                 <h3 className="font-bold text-slate-800 dark:text-slate-100">{surah.englishName}</h3>
                                 <p className="text-xs text-slate-500 dark:text-slate-400">{surah.englishNameTranslation} • {surah.numberOfAyahs} Verses</p>
                             </div>
                             <div className="text-right">
                                 <span className="font-arabic text-xl text-slate-700 dark:text-slate-200">{surah.name.replace('سُورَةُ ', '')}</span>
                             </div>
                          </button>
                      ))}
                  </div>
              )}
           </div>
        </div>
     );
  }

  // Render Detail
  return (
      <div className="h-full flex flex-col animate-fade-in bg-white dark:bg-slate-950 relative">
          <audio ref={audioRef} className="hidden" />

          {/* Header */}
          <div className="px-4 py-4 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between sticky top-0 bg-white/95 dark:bg-slate-950/95 backdrop-blur-sm z-20 transition-colors">
              <button 
                onClick={handleBack}
                className="w-10 h-10 rounded-full hover:bg-slate-100 dark:hover:bg-slate-900 flex items-center justify-center text-slate-600 dark:text-slate-300 transition-colors"
              >
                  <ArrowLeft size={22} />
              </button>
              <div className="text-center">
                  <h2 className="font-bold text-slate-800 dark:text-slate-100">{activeSurah.englishName}</h2>
                  <p className="text-xs text-slate-500 dark:text-slate-400">{activeSurah.englishNameTranslation}</p>
              </div>
              <button 
                onClick={() => setShowReciterList(true)}
                className={`w-10 h-10 rounded-full hover:bg-slate-100 dark:hover:bg-slate-900 flex items-center justify-center transition-colors ${isPlaying || audioUrls.length > 0 ? 'text-emerald-600 dark:text-emerald-400' : 'text-slate-600 dark:text-slate-300'}`}
              >
                  <Headphones size={22} />
              </button>
          </div>

          <div ref={topRef} className={`flex-1 overflow-y-auto pb-32 scroll-smooth ${showReciterList ? 'overflow-hidden' : ''}`}>
               {/* Bismillah Header - Show for all except At-Tawbah (9) */}
               {activeSurah.number !== 9 && !loadingSurah && (
                   <div className="py-8 flex justify-center text-slate-800 dark:text-slate-100 opacity-80">
                       <p className="font-arabic text-3xl">بِسْمِ ٱللَّٰهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ</p>
                   </div>
               )}

               {loadingSurah ? (
                   <div className="flex flex-col items-center justify-center py-32 space-y-4">
                       <Loader2 className="animate-spin text-emerald-600" size={32} />
                       <p className="text-sm text-slate-400">Loading verses...</p>
                   </div>
               ) : (
                   <div className="px-6 space-y-8 pb-10">
                       {ayahs.map((ayah, idx) => {
                           const isActive = currentAudioIndex === idx && isPlaying;
                           return (
                               <div key={idx} id={`ayah-${ayah.number}`} className={`transition-all duration-300 ${isActive ? 'scale-[1.02]' : ''}`}>
                                   {/* Arabic */}
                                   <div className={`w-full p-6 rounded-2xl mb-4 border transition-colors duration-300 ${isActive ? 'bg-emerald-50 dark:bg-emerald-900/20 border-emerald-200 dark:border-emerald-800' : 'bg-slate-50 dark:bg-slate-900/40 border-slate-100 dark:border-slate-800/50'}`}>
                                       <p className={`text-right font-arabic text-3xl leading-[2.5] ${isActive ? 'text-emerald-800 dark:text-emerald-100' : 'text-slate-800 dark:text-slate-100'}`} dir="rtl">
                                           {ayah.arabic} 
                                           <span className={`inline-flex items-center justify-center w-8 h-8 mx-2 text-sm border rounded-full font-sans number-symbol align-middle ${isActive ? 'bg-emerald-100 dark:bg-emerald-800 text-emerald-700 dark:text-emerald-200 border-emerald-300 dark:border-emerald-700' : 'bg-white dark:bg-slate-800 text-emerald-600 dark:text-emerald-400 border-emerald-500/50'}`}>
                                               {ayah.number}
                                           </span>
                                       </p>
                                   </div>

                                   {/* Translation */}
                                   <div className="px-2">
                                       <p className={`leading-relaxed text-lg transition-colors ${isActive ? 'text-slate-800 dark:text-slate-200 font-medium' : 'text-slate-600 dark:text-slate-300'}`}>
                                           {ayah.translation}
                                       </p>
                                   </div>

                                   {idx < ayahs.length - 1 && (
                                       <div className="my-8 border-b border-slate-100 dark:border-slate-800/60 w-1/2 mx-auto"></div>
                                   )}
                               </div>
                           );
                       })}
                   </div>
               )}
          </div>

          {/* Audio Player Bar */}
          <div className="absolute bottom-0 left-0 right-0 bg-white dark:bg-slate-900 border-t border-slate-200 dark:border-slate-800 p-4 shadow-[0_-4px_10px_rgba(0,0,0,0.05)] z-30 transition-transform duration-300 flex items-center justify-between gap-4">
               <div className="flex flex-col min-w-0">
                   <span className="text-xs font-bold text-emerald-600 dark:text-emerald-400 uppercase tracking-wider">Now Playing</span>
                   <span className="text-sm font-semibold text-slate-800 dark:text-slate-100 truncate">{activeReciter.name}</span>
               </div>

               <div className="flex items-center gap-4">
                    <button 
                        onClick={() => setCurrentAudioIndex(prev => Math.max(0, prev - 1))}
                        className="text-slate-400 hover:text-slate-600 dark:hover:text-slate-200"
                        disabled={currentAudioIndex <= 0}
                    >
                        <SkipBack size={20} className="fill-current" />
                    </button>

                    <button 
                        onClick={togglePlay}
                        disabled={loadingAudio}
                        className="w-12 h-12 bg-emerald-600 hover:bg-emerald-700 text-white rounded-full flex items-center justify-center shadow-lg shadow-emerald-600/30 active:scale-95 transition-all"
                    >
                        {loadingAudio ? (
                            <Loader2 size={20} className="animate-spin" />
                        ) : isPlaying ? (
                            <Pause size={20} className="fill-current" />
                        ) : (
                            <Play size={20} className="fill-current ml-1" />
                        )}
                    </button>

                    <button 
                         onClick={() => setCurrentAudioIndex(prev => Math.min((audioUrls.length || ayahs.length) - 1, prev + 1))}
                         className="text-slate-400 hover:text-slate-600 dark:hover:text-slate-200"
                         disabled={currentAudioIndex >= (audioUrls.length || ayahs.length) - 1}
                    >
                        <SkipForward size={20} className="fill-current" />
                    </button>
               </div>
          </div>

          {/* Reciter Selection Modal */}
          {showReciterList && (
              <div className="absolute inset-0 z-40 bg-white dark:bg-slate-950 flex flex-col animate-fade-in">
                  <div className="p-4 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between bg-white dark:bg-slate-950">
                      <h3 className="font-bold text-lg text-slate-800 dark:text-slate-100">Select Reciter</h3>
                      <button onClick={() => setShowReciterList(false)} className="p-2 bg-slate-100 dark:bg-slate-900 rounded-full text-slate-500 hover:text-slate-800 dark:hover:text-slate-200">
                          <X size={20} />
                      </button>
                  </div>
                  <div className="flex-1 overflow-y-auto p-4 space-y-2">
                      {reciters.length === 0 && <div className="text-center p-10"><Loader2 className="animate-spin mx-auto text-emerald-500" /></div>}
                      {reciters.map((reciter) => (
                          <button
                              key={reciter.identifier}
                              onClick={() => handleReciterChange(reciter)}
                              className={`w-full p-4 rounded-xl flex items-center justify-between text-left transition-all ${activeReciter.identifier === reciter.identifier ? 'bg-emerald-50 dark:bg-emerald-900/20 border border-emerald-200 dark:border-emerald-800' : 'bg-white dark:bg-slate-900 border border-slate-100 dark:border-slate-800 hover:border-emerald-200 dark:hover:border-emerald-800'}`}
                          >
                              <div>
                                  <p className={`font-semibold ${activeReciter.identifier === reciter.identifier ? 'text-emerald-700 dark:text-emerald-400' : 'text-slate-700 dark:text-slate-200'}`}>
                                      {reciter.englishName}
                                  </p>
                                  <p className="text-xs text-slate-400 dark:text-slate-500">{reciter.name}</p>
                              </div>
                              {activeReciter.identifier === reciter.identifier && <Check size={18} className="text-emerald-600" />}
                          </button>
                      ))}
                  </div>
              </div>
          )}
      </div>
  );
};

export default QuranReader;

import React, { useState, useEffect, useRef } from 'react';
import { Search, ArrowLeft, Loader2, AlertCircle, BookOpen, Clock, Play, Pause, SkipForward, SkipBack, X, Headphones, Check } from 'lucide-react';

interface Surah {
  number: number;
  name: string;
  englishName: string;
  englishNameTranslation: string;
  numberOfAyahs: number;
  revelationType: string;
}

interface LastRead {
  number: number;
  name: string;
  englishName: string;
  timestamp: number;
}

interface Reciter {
  identifier: string;
  name: string;
  englishName: string;
  format: string;
  language: string;
}

const QuranReader: React.FC = () => {
  const [surahs, setSurahs] = useState<Surah[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [searchTerm, setSearchTerm] = useState('');
  const [activeSurah, setActiveSurah] = useState<Surah | null>(null);
  const [ayahs, setAyahs] = useState<{arabic: string, translation: string, number: number}[]>([]);
  const [loadingSurah, setLoadingSurah] = useState(false);
  const [lastRead, setLastRead] = useState<LastRead | null>(null);

  // Audio State
  const [reciters, setReciters] = useState<Reciter[]>([]);
  const [activeReciter, setActiveReciter] = useState<Reciter>({ 
      identifier: 'ar.alafasy', 
      name: 'Mishary Rashid Alafasy', 
      englishName: 'Alafasy', 
      format: 'audio',
      language: 'ar'
  });
  const [showReciterList, setShowReciterList] = useState(false);
  const [audioUrls, setAudioUrls] = useState<string[]>([]);
  const [currentAudioIndex, setCurrentAudioIndex] = useState(-1);
  const [isPlaying, setIsPlaying] = useState(false);
  const [loadingAudio, setLoadingAudio] = useState(false);

  const topRef = useRef<HTMLDivElement>(null);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  // Fetch Surah List & Last Read & Reciters
  useEffect(() => {
    const fetchData = async () => {
      try {
        // Load Last Read
        const savedProgress = localStorage.getItem('quran_last_read');
        if (savedProgress) {
            setLastRead(JSON.parse(savedProgress));
        }

        // Load Reciters
        const cachedReciters = localStorage.getItem('quran_reciters');
        if (cachedReciters) {
            setReciters(JSON.parse(cachedReciters));
        } else {
            // Fetch Reciters
            fetch('https://api.alquran.cloud/v1/edition?format=audio&language=ar&type=versebyverse')
                .then(res => res.json())
                .then(data => {
                    if (data.code === 200) {
                        setReciters(data.data);
                        localStorage.setItem('quran_reciters', JSON.stringify(data.data));
                    }
                })
                .catch(console.error);
        }

        const cached = localStorage.getItem('quran_surahs');
        if (cached) {
            setSurahs(JSON.parse(cached));
            setLoading(false);
            return;
        }

        const res = await fetch('https://api.alquran.cloud/v1/surah');
        const data = await res.json();
        if (data.code === 200) {
          setSurahs(data.data);
          localStorage.setItem('quran_surahs', JSON.stringify(data.data));
        } else {
          setError('Failed to load Surahs');
        }
      } catch (err) {
        setError('Network error. Please check connection.');
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, []);

  // Fetch Specific Surah
  const selectSurah = async (surah: Surah) => {
    setActiveSurah(surah);
    setLoadingSurah(true);
    setAyahs([]);
    resetAudio();

    // Save Progress
    const progress: LastRead = {
        number: surah.number,
        name: surah.name,
        englishName: surah.englishName,
        timestamp: Date.now()
    };
    setLastRead(progress);
    localStorage.setItem('quran_last_read', JSON.stringify(progress));

    try {
       // Fetch Arabic and English
       const res = await fetch(`https://api.alquran.cloud/v1/surah/${surah.number}/editions/quran-uthmani,en.sahih`);
       const data = await res.json();

       if (data.code === 200 && data.data.length >= 2) {
           const arabicAyahs = data.data[0].ayahs;
           const englishAyahs = data.data[1].ayahs;

           const combined = arabicAyahs.map((ayah: any, index: number) => ({
               number: ayah.numberInSurah,
               arabic: ayah.text,
               translation: englishAyahs[index]?.text || ''
           }));

           setAyahs(combined);

           // Pre-fetch audio URLs for this surah/reciter combo roughly
           // Not blocking the UI, but ensuring we have them if play is clicked immediately
           loadAudioForSurah(surah.number, activeReciter.identifier);
       }
    } catch (err) {
        console.error(err);
        setError('Failed to load verses.');
    } finally {
        setLoadingSurah(false);
        if(topRef.current) topRef.current.scrollTop = 0;
    }
  };

  const handleBack = () => {
    setActiveSurah(null);
    setAyahs([]);
    resetAudio();
  };

  // Audio Functions
  const resetAudio = () => {
      setIsPlaying(false);
      setCurrentAudioIndex(-1);
      setAudioUrls([]);
      if (audioRef.current) {
          audioRef.current.pause();
          audioRef.current.currentTime = 0;
      }
  };

  const togglePlay = async () => {
      if (loadingAudio) return;

      if (isPlaying) {
          audioRef.current?.pause();
          setIsPlaying(false);
      } else {
          // If no audio urls yet (maybe fetch failed or didn't happen), try fetching
          if (audioUrls.length === 0 && activeSurah) {
              await loadAudioForSurah(activeSurah.number, activeReciter.identifier);
          }

          if (currentAudioIndex === -1) {
              setCurrentAudioIndex(0);
          } else {
              audioRef.current?.play();
          }
          setIsPlaying(true);
      }
  };

  const loadAudioForSurah = async (surahNumber: number, reciterId: string) => {
      setLoadingAudio(true);
      try {
          const res = await fetch(`https://api.alquran.cloud/v1/surah/${surahNumber}/${reciterId}`);
          const data = await res.json();
          if (data.code === 200) {
              const urls = data.data.ayahs.map((a: any) => a.audio);
              setAudioUrls(urls);
          }
      } catch (err) {
          console.error("Error loading audio", err);
          // Don't alert immediately on background load, but handle play failure
      } finally {
          setLoadingAudio(false);
      }
  };

  const handleReciterChange = async (reciter: Reciter) => {
      setActiveReciter(reciter);
      setShowReciterList(false);

      // If inside a surah, reload audio
      if (activeSurah) {
          // Stop current playback
          const wasPlaying = isPlaying;
          setIsPlaying(false);
          if(audioRef.current) audioRef.current.pause();

          // Load new audio
          await loadAudioForSurah(activeSurah.number, reciter.identifier);

          // If it was playing, resume from same index (if valid)
          if (wasPlaying && currentAudioIndex !== -1) {
              setIsPlaying(true);
              // The effect will handle the src change
          }
      }
  };

  // Audio Player Effect
  useEffect(() => {
      const audio = audioRef.current;
      if (!audio) return;

      const playCurrentVerse = async () => {
          if (currentAudioIndex >= 0 && currentAudioIndex < audioUrls.length && isPlaying) {
              const url = audioUrls[currentAudioIndex];
              // Only update src if it's different to avoid reloading
              if (audio.src !== url) {
                  audio.src = url;
              }

              try {
                  await audio.play();
                  // Scroll to verse
                  document.getElementById(`ayah-${currentAudioIndex + 1}`)?.scrollIntoView({ behavior: 'smooth', block: 'center' });
              } catch (e) {
                  console.error("Play failed", e);
                  setIsPlaying(false);
              }
          }
      };

      if (isPlaying) {
          playCurrentVerse();
      }

      const handleEnded = () => {
          if (currentAudioIndex < audioUrls.length - 1) {
              setCurrentAudioIndex(prev => prev + 1);
          } else {
              setIsPlaying(false);
              setCurrentAudioIndex(0); // Reset to start
          }
      };

      audio.addEventListener('ended', handleEnded);
      return () => audio.removeEventListener('ended', handleEnded);
  }, [currentAudioIndex, audioUrls, isPlaying]);


  const filteredSurahs = surahs.filter(s => 
    s.englishName.toLowerCase().includes(searchTerm.toLowerCase()) || 
    s.englishNameTranslation.toLowerCase().includes(searchTerm.toLowerCase()) ||
    s.number.toString().includes(searchTerm)
  );

  const continueReading = () => {
      if (lastRead) {
          const surah = surahs.find(s => s.number === lastRead.number);
          if (surah) selectSurah(surah);
      }
  };

  // Render List
  if (!activeSurah) {
     return (
        <div className="h-full flex flex-col animate-fade-in relative">
           <div className="px-6 pt-2 pb-4 bg-white dark:bg-slate-950 sticky top-0 z-10">
              <h1 className="text-2xl font-bold text-slate-800 dark:text-slate-100 mb-4">The Noble Quran</h1>
              <div className="relative">
                 <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                 <input 
                   type="text" 
                   placeholder="Search Surah..." 
                   className="w-full bg-slate-100 dark:bg-slate-900 border-none rounded-xl py-3 pl-10 pr-4 text-slate-800 dark:text-slate-100 placeholder:text-slate-400 focus:ring-2 focus:ring-emerald-500/50 outline-none transition-all"
                   value={searchTerm}
                   onChange={(e) => setSearchTerm(e.target.value)}
                 />
              </div>
           </div>

           <div className="flex-1 overflow-y-auto px-6 pb-24">
              {loading ? (
                  <div className="flex justify-center pt-10"><Loader2 className="animate-spin text-emerald-600" /></div>
              ) : error ? (
                  <div className="flex flex-col items-center justify-center pt-10 text-center">
                    <AlertCircle className="text-red-500 mb-2" />
                    <p className="text-slate-600 dark:text-slate-400">{error}</p>
                    <button onClick={() => window.location.reload()} className="mt-4 text-emerald-600 font-medium">Retry</button>
                  </div>
              ) : (
                  <div className="space-y-3">
                      {/* Last Read Card */}
                      {lastRead && !searchTerm && (
                          <div className="mb-6 animate-fade-in">
                              <h2 className="text-xs font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wider mb-3 px-1">Continue Reading</h2>
                              <button 
                                  onClick={continueReading}
                                  className="w-full bg-gradient-to-r from-emerald-600 to-teal-700 p-5 rounded-2xl text-white shadow-lg shadow-emerald-600/20 flex items-center justify-between group transform transition-all active:scale-[0.98]"
                              >
                                  <div className="flex items-center gap-4">
                                      <div className="w-12 h-12 bg-white/20 backdrop-blur-sm rounded-full flex items-center justify-center shadow-inner">
                                          <BookOpen size={22} className="text-white" />
                                      </div>
                                      <div className="text-left">
                                          <p className="text-emerald-100 text-xs font-medium mb-1 flex items-center gap-1">
                                            <Clock size={10} /> Last Read
                                          </p>
                                          <p className="font-bold text-xl">{lastRead.englishName}</p>
                                      </div>
                                  </div>
                                  <div className="font-arabic text-3xl opacity-80 text-emerald-100">{lastRead.name.replace('سُورَةُ ', '')}</div>
                              </button>
                          </div>
                      )}

                      {/* Surah List */}
                      {searchTerm && <h2 className="text-xs font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wider mb-3 px-1">Search Results</h2>}

                      {filteredSurahs.map(surah => (
                          <button 
                            key={surah.number}
                            onClick={() => selectSurah(surah)}
                            className="w-full bg-white dark:bg-slate-900 p-4 rounded-2xl border border-slate-100 dark:border-slate-800 hover:border-emerald-200 dark:hover:border-emerald-800 hover:shadow-sm transition-all flex items-center gap-4 text-left group"
                          >
                             <div className="w-10 h-10 bg-slate-50 dark:bg-slate-800 rounded-lg flex items-center justify-center font-bold text-slate-400 dark:text-slate-500 group-hover:text-emerald-600 dark:group-hover:text-emerald-400 group-hover:bg-emerald-50 dark:group-hover:bg-emerald-900/20 transition-colors">
                                 {surah.number}
                             </div>
                             <div className="flex-1">
                                 <h3 className="font-bold text-slate-800 dark:text-slate-100">{surah.englishName}</h3>
                                 <p className="text-xs text-slate-500 dark:text-slate-400">{surah.englishNameTranslation} • {surah.numberOfAyahs} Verses</p>
                             </div>
                             <div className="text-right">
                                 <span className="font-arabic text-xl text-slate-700 dark:text-slate-200">{surah.name.replace('سُورَةُ ', '')}</span>
                             </div>
                          </button>
                      ))}
                  </div>
              )}
           </div>
        </div>
     );
  }

  // Render Detail
  return (
      <div className="h-full flex flex-col animate-fade-in bg-white dark:bg-slate-950 relative">
          <audio ref={audioRef} className="hidden" preload="auto" />

          {/* Header */}
          <div className="px-4 py-4 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between sticky top-0 bg-white/95 dark:bg-slate-950/95 backdrop-blur-sm z-20 transition-colors">
              <button 
                onClick={handleBack}
                className="w-10 h-10 rounded-full hover:bg-slate-100 dark:hover:bg-slate-900 flex items-center justify-center text-slate-600 dark:text-slate-300 transition-colors"
              >
                  <ArrowLeft size={22} />
              </button>
              <div className="text-center">
                  <h2 className="font-bold text-slate-800 dark:text-slate-100">{activeSurah.englishName}</h2>
                  <p className="text-xs text-slate-500 dark:text-slate-400">{activeSurah.englishNameTranslation}</p>
              </div>
              <button 
                onClick={() => setShowReciterList(true)}
                className={`w-10 h-10 rounded-full hover:bg-slate-100 dark:hover:bg-slate-900 flex items-center justify-center transition-colors ${isPlaying || audioUrls.length > 0 ? 'text-emerald-600 dark:text-emerald-400' : 'text-slate-600 dark:text-slate-300'}`}
              >
                  <Headphones size={22} />
              </button>
          </div>

          <div ref={topRef} className={`flex-1 overflow-y-auto pb-32 scroll-smooth ${showReciterList ? 'overflow-hidden' : ''}`}>
               {/* Bismillah Header - Show for all except At-Tawbah (9) */}
               {activeSurah.number !== 9 && !loadingSurah && (
                   <div className="py-8 flex justify-center text-slate-800 dark:text-slate-100 opacity-80">
                       <p className="font-arabic text-3xl">بِسْمِ ٱللَّٰهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ</p>
                   </div>
               )}

               {loadingSurah ? (
                   <div className="flex flex-col items-center justify-center py-32 space-y-4">
                       <Loader2 className="animate-spin text-emerald-600" size={32} />
                       <p className="text-sm text-slate-400">Loading verses...</p>
                   </div>
               ) : (
                   <div className="px-6 space-y-8 pb-10">
                       {ayahs.map((ayah, idx) => {
                           const isActive = currentAudioIndex === idx && isPlaying;
                           return (
                               <div key={idx} id={`ayah-${ayah.number}`} className={`transition-all duration-300 ${isActive ? 'scale-[1.02]' : ''}`}>
                                   {/* Arabic */}
                                   <div className={`w-full p-6 rounded-2xl mb-4 border transition-colors duration-300 ${isActive ? 'bg-emerald-50 dark:bg-emerald-900/20 border-emerald-200 dark:border-emerald-800' : 'bg-slate-50 dark:bg-slate-900/40 border-slate-100 dark:border-slate-800/50'}`}>
                                       <p className={`text-right font-arabic text-3xl leading-[2.5] ${isActive ? 'text-emerald-800 dark:text-emerald-100' : 'text-slate-800 dark:text-slate-100'}`} dir="rtl">
                                           {ayah.arabic} 
                                           <span className={`inline-flex items-center justify-center w-8 h-8 mx-2 text-sm border rounded-full font-sans number-symbol align-middle ${isActive ? 'bg-emerald-100 dark:bg-emerald-800 text-emerald-700 dark:text-emerald-200 border-emerald-300 dark:border-emerald-700' : 'bg-white dark:bg-slate-800 text-emerald-600 dark:text-emerald-400 border-emerald-500/50'}`}>
                                               {ayah.number}
                                           </span>
                                       </p>
                                   </div>

                                   {/* Translation */}
                                   <div className="px-2">
                                       <p className={`leading-relaxed text-lg transition-colors ${isActive ? 'text-slate-800 dark:text-slate-200 font-medium' : 'text-slate-600 dark:text-slate-300'}`}>
                                           {ayah.translation}
                                       </p>
                                   </div>

                                   {idx < ayahs.length - 1 && (
                                       <div className="my-8 border-b border-slate-100 dark:border-slate-800/60 w-1/2 mx-auto"></div>
                                   )}
                               </div>
                           );
                       })}
                   </div>
               )}
          </div>

          {/* Audio Player Bar */}
          <div className="absolute bottom-0 left-0 right-0 bg-white dark:bg-slate-900 border-t border-slate-200 dark:border-slate-800 p-4 shadow-[0_-4px_10px_rgba(0,0,0,0.05)] z-30 transition-transform duration-300 flex items-center justify-between gap-4">
               <div className="flex flex-col min-w-0">
                   <span className="text-xs font-bold text-emerald-600 dark:text-emerald-400 uppercase tracking-wider">Now Playing</span>
                   <span className="text-sm font-semibold text-slate-800 dark:text-slate-100 truncate">{activeReciter.name}</span>
               </div>

               <div className="flex items-center gap-4">
                    <button 
                        onClick={() => setCurrentAudioIndex(prev => Math.max(0, prev - 1))}
                        className="text-slate-400 hover:text-slate-600 dark:hover:text-slate-200"
                        disabled={currentAudioIndex <= 0}
                    >
                        <SkipBack size={20} className="fill-current" />
                    </button>

                    <button 
                        onClick={togglePlay}
                        disabled={loadingAudio}
                        className="w-12 h-12 bg-emerald-600 hover:bg-emerald-700 text-white rounded-full flex items-center justify-center shadow-lg shadow-emerald-600/30 active:scale-95 transition-all"
                    >
                        {loadingAudio ? (
                            <Loader2 size={20} className="animate-spin" />
                        ) : isPlaying ? (
                            <Pause size={20} className="fill-current" />
                        ) : (
                            <Play size={20} className="fill-current ml-1" />
                        )}
                    </button>

                    <button 
                         onClick={() => setCurrentAudioIndex(prev => Math.min((audioUrls.length || ayahs.length) - 1, prev + 1))}
                         className="text-slate-400 hover:text-slate-600 dark:hover:text-slate-200"
                         disabled={currentAudioIndex >= (audioUrls.length || ayahs.length) - 1}
                    >
                        <SkipForward size={20} className="fill-current" />
                    </button>
               </div>
          </div>

          {/* Reciter Selection Modal */}
          {showReciterList && (
              <div className="absolute inset-0 z-40 bg-white dark:bg-slate-950 flex flex-col animate-fade-in">
                  <div className="p-4 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between bg-white dark:bg-slate-950">
                      <h3 className="font-bold text-lg text-slate-800 dark:text-slate-100">Select Reciter</h3>
                      <button onClick={() => setShowReciterList(false)} className="p-2 bg-slate-100 dark:bg-slate-900 rounded-full text-slate-500 hover:text-slate-800 dark:hover:text-slate-200">
                          <X size={20} />
                      </button>
                  </div>
                  <div className="flex-1 overflow-y-auto p-4 space-y-2">
                      {reciters.length === 0 && <div className="text-center p-10"><Loader2 className="animate-spin mx-auto text-emerald-500" /></div>}
                      {reciters.map((reciter) => (
                          <button
                              key={reciter.identifier}
                              onClick={() => handleReciterChange(reciter)}
                              className={`w-full p-4 rounded-xl flex items-center justify-between text-left transition-all ${activeReciter.identifier === reciter.identifier ? 'bg-emerald-50 dark:bg-emerald-900/20 border border-emerald-200 dark:border-emerald-800' : 'bg-white dark:bg-slate-900 border border-slate-100 dark:border-slate-800 hover:border-emerald-200 dark:hover:border-emerald-800'}`}
                          >
                              <div>
                                  <p className={`font-semibold ${activeReciter.identifier === reciter.identifier ? 'text-emerald-700 dark:text-emerald-400' : 'text-slate-700 dark:text-slate-200'}`}>
                                      {reciter.englishName}
                                  </p>
                                  <p className="text-xs text-slate-400 dark:text-slate-500">{reciter.name}</p>
                              </div>
                              {activeReciter.identifier === reciter.identifier && <Check size={18} className="text-emerald-600" />}
                          </button>
                      ))}
                  </div>
              </div>
          )}
      </div>
  );
};

export default QuranReader;

import React, { useState, useEffect, useRef } from 'react';
import { Search, ArrowLeft, Loader2, AlertCircle, BookOpen, Clock, Play, Pause, SkipForward, SkipBack, X, Headphones, Check, CheckCircle2 } from 'lucide-react';

interface Surah {
  number: number;
  name: string;
  englishName: string;
  englishNameTranslation: string;
  numberOfAyahs: number;
  revelationType: string;
}

interface LastRead {
  number: number;
  name: string;
  englishName: string;
  timestamp: number;
}

interface Reciter {
  identifier: string;
  name: string;
  englishName: string;
  format: string;
  language: string;
}

const QuranReader: React.FC = () => {
  const [surahs, setSurahs] = useState<Surah[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [searchTerm, setSearchTerm] = useState('');
  const [activeSurah, setActiveSurah] = useState<Surah | null>(null);
  const [ayahs, setAyahs] = useState<{arabic: string, translation: string, number: number}[]>([]);
  const [loadingSurah, setLoadingSurah] = useState(false);
  const [lastRead, setLastRead] = useState<LastRead | null>(null);
  const [progress, setProgress] = useState<Record<number, number>>({});

  // Audio State
  const [reciters, setReciters] = useState<Reciter[]>([]);
  const [activeReciter, setActiveReciter] = useState<Reciter>({ 
      identifier: 'ar.alafasy', 
      name: 'Mishary Rashid Alafasy', 
      englishName: 'Alafasy', 
      format: 'audio',
      language: 'ar'
  });
  const [showReciterList, setShowReciterList] = useState(false);
  const [audioUrls, setAudioUrls] = useState<string[]>([]);
  const [currentAudioIndex, setCurrentAudioIndex] = useState(-1);
  const [isPlaying, setIsPlaying] = useState(false);
  const [loadingAudio, setLoadingAudio] = useState(false);

  const topRef = useRef<HTMLDivElement>(null);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  // Fetch Data & Initialize
  useEffect(() => {
    const fetchData = async () => {
      try {
        // Load Persisted Data
        const savedProgress = localStorage.getItem('quran_last_read');
        if (savedProgress) setLastRead(JSON.parse(savedProgress));

        const savedReadingProgress = localStorage.getItem('quran_reading_progress');
        if (savedReadingProgress) setProgress(JSON.parse(savedReadingProgress));

        const cachedReciters = localStorage.getItem('quran_reciters');
        if (cachedReciters) {
            setReciters(JSON.parse(cachedReciters));
        } else {
            fetch('https://api.alquran.cloud/v1/edition?format=audio&language=ar&type=versebyverse')
                .then(res => res.json())
                .then(data => {
                    if (data.code === 200) {
                        setReciters(data.data);
                        localStorage.setItem('quran_reciters', JSON.stringify(data.data));
                    }
                })
                .catch(console.error);
        }

        const cached = localStorage.getItem('quran_surahs');
        if (cached) {
            setSurahs(JSON.parse(cached));
            setLoading(false);
            return;
        }

        const res = await fetch('https://api.alquran.cloud/v1/surah');
        const data = await res.json();
        if (data.code === 200) {
          setSurahs(data.data);
          localStorage.setItem('quran_surahs', JSON.stringify(data.data));
        } else {
          setError('Failed to load Surahs');
        }
      } catch (err) {
        setError('Network error. Please check connection.');
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, []);

  // Save Progress Effect
  useEffect(() => {
    localStorage.setItem('quran_reading_progress', JSON.stringify(progress));
  }, [progress]);

  // Intersection Observer for Progress Tracking
  useEffect(() => {
    if (!activeSurah || loadingSurah || ayahs.length === 0) return;

    const observer = new IntersectionObserver((entries) => {
      entries.forEach(entry => {
        if (entry.isIntersecting) {
          const ayahNum = parseInt(entry.target.getAttribute('data-ayah-number') || '0');
          if (ayahNum > 0) {
             setProgress(prev => {
                const currentMax = prev[activeSurah.number] || 0;
                // Only update if we've read further
                if (ayahNum > currentMax) {
                   return { ...prev, [activeSurah.number]: ayahNum };
                }
                return prev;
             });
          }
        }
      });
    }, { threshold: 0.6 }); // Verse must be 60% visible to count as "reading"

    // Observe after a slight delay to ensure render
    setTimeout(() => {
        document.querySelectorAll('.ayah-item').forEach(el => observer.observe(el));
    }, 500);

    return () => observer.disconnect();
  }, [activeSurah, loadingSurah, ayahs]);

  // Fetch Specific Surah
  const selectSurah = async (surah: Surah) => {
    setActiveSurah(surah);
    setLoadingSurah(true);
    setAyahs([]);
    resetAudio();

    const progressRecord: LastRead = {
        number: surah.number,
        name: surah.name,
        englishName: surah.englishName,
        timestamp: Date.now()
    };
    setLastRead(progressRecord);
    localStorage.setItem('quran_last_read', JSON.stringify(progressRecord));

    try {
       const res = await fetch(`https://api.alquran.cloud/v1/surah/${surah.number}/editions/quran-uthmani,en.sahih`);
       const data = await res.json();

       if (data.code === 200 && data.data.length >= 2) {
           const arabicAyahs = data.data[0].ayahs;
           const englishAyahs = data.data[1].ayahs;

           const combined = arabicAyahs.map((ayah: any, index: number) => ({
               number: ayah.numberInSurah,
               arabic: ayah.text,
               translation: englishAyahs[index]?.text || ''
           }));

           setAyahs(combined);
           loadAudioForSurah(surah.number, activeReciter.identifier);
       }
    } catch (err) {
        console.error(err);
        setError('Failed to load verses.');
    } finally {
        setLoadingSurah(false);
        if(topRef.current) topRef.current.scrollTop = 0;
    }
  };

  const handleBack = () => {
    setActiveSurah(null);
    setAyahs([]);
    resetAudio();
  };

  // Audio Functions
  const resetAudio = () => {
      setIsPlaying(false);
      setCurrentAudioIndex(-1);
      setAudioUrls([]);
      if (audioRef.current) {
          audioRef.current.pause();
          audioRef.current.currentTime = 0;
      }
  };

  const togglePlay = async () => {
      if (loadingAudio) return;

      if (isPlaying) {
          audioRef.current?.pause();
          setIsPlaying(false);
      } else {
          if (audioUrls.length === 0 && activeSurah) {
              await loadAudioForSurah(activeSurah.number, activeReciter.identifier);
          }

          if (currentAudioIndex === -1) {
              // Start from the first unread verse if available, else 0
              const lastReadAyah = progress[activeSurah!.number] || 0;
              // If completed, start from 0, else start from last read (optional logic, kept simple to 0 for now unless we want smart resume)
              setCurrentAudioIndex(0); 
          } else {
              audioRef.current?.play();
          }
          setIsPlaying(true);
      }
  };

  const loadAudioForSurah = async (surahNumber: number, reciterId: string) => {
      setLoadingAudio(true);
      try {
          const res = await fetch(`https://api.alquran.cloud/v1/surah/${surahNumber}/${reciterId}`);
          const data = await res.json();
          if (data.code === 200) {
              const urls = data.data.ayahs.map((a: any) => a.audio);
              setAudioUrls(urls);
          }
      } catch (err) {
          console.error("Error loading audio", err);
      } finally {
          setLoadingAudio(false);
      }
  };

  const handleReciterChange = async (reciter: Reciter) => {
      setActiveReciter(reciter);
      setShowReciterList(false);
      if (activeSurah) {
          const wasPlaying = isPlaying;
          setIsPlaying(false);
          if(audioRef.current) audioRef.current.pause();
          await loadAudioForSurah(activeSurah.number, reciter.identifier);
          if (wasPlaying && currentAudioIndex !== -1) {
              setIsPlaying(true);
          }
      }
  };

  useEffect(() => {
      const audio = audioRef.current;
      if (!audio) return;

      const playCurrentVerse = async () => {
          if (currentAudioIndex >= 0 && currentAudioIndex < audioUrls.length && isPlaying) {
              const url = audioUrls[currentAudioIndex];
              if (audio.src !== url) audio.src = url;
              try {
                  await audio.play();
                  document.getElementById(`ayah-${currentAudioIndex + 1}`)?.scrollIntoView({ behavior: 'smooth', block: 'center' });
              } catch (e) {
                  console.error("Play failed", e);
                  setIsPlaying(false);
              }
          }
      };

      if (isPlaying) playCurrentVerse();

      const handleEnded = () => {
          if (currentAudioIndex < audioUrls.length - 1) {
              setCurrentAudioIndex(prev => prev + 1);
          } else {
              setIsPlaying(false);
              setCurrentAudioIndex(0);
          }
      };

      audio.addEventListener('ended', handleEnded);
      return () => audio.removeEventListener('ended', handleEnded);
  }, [currentAudioIndex, audioUrls, isPlaying]);


  const filteredSurahs = surahs.filter(s => 
    s.englishName.toLowerCase().includes(searchTerm.toLowerCase()) || 
    s.englishNameTranslation.toLowerCase().includes(searchTerm.toLowerCase()) ||
    s.number.toString().includes(searchTerm)
  );

  const continueReading = () => {
      if (lastRead) {
          const surah = surahs.find(s => s.number === lastRead.number);
          if (surah) selectSurah(surah);
      }
  };

  // Render List
  if (!activeSurah) {
     return (
        <div className="h-full flex flex-col animate-fade-in relative">
           <div className="px-6 pt-2 pb-4 bg-white dark:bg-slate-950 sticky top-0 z-10">
              <h1 className="text-2xl font-bold text-slate-800 dark:text-slate-100 mb-4">The Noble Quran</h1>
              <div className="relative">
                 <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                 <input 
                   type="text" 
                   placeholder="Search Surah..." 
                   className="w-full bg-slate-100 dark:bg-slate-900 border-none rounded-xl py-3 pl-10 pr-4 text-slate-800 dark:text-slate-100 placeholder:text-slate-400 focus:ring-2 focus:ring-emerald-500/50 outline-none transition-all"
                   value={searchTerm}
                   onChange={(e) => setSearchTerm(e.target.value)}
                 />
              </div>
           </div>

           <div className="flex-1 overflow-y-auto px-6 pb-24">
              {loading ? (
                  <div className="flex justify-center pt-10"><Loader2 className="animate-spin text-emerald-600" /></div>
              ) : error ? (
                  <div className="flex flex-col items-center justify-center pt-10 text-center">
                    <AlertCircle className="text-red-500 mb-2" />
                    <p className="text-slate-600 dark:text-slate-400">{error}</p>
                    <button onClick={() => window.location.reload()} className="mt-4 text-emerald-600 font-medium">Retry</button>
                  </div>
              ) : (
                  <div className="space-y-3">
                      {/* Last Read Card */}
                      {lastRead && !searchTerm && (
                          <div className="mb-6 animate-fade-in">
                              <h2 className="text-xs font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wider mb-3 px-1">Continue Reading</h2>
                              <button 
                                  onClick={continueReading}
                                  className="w-full bg-gradient-to-r from-emerald-600 to-teal-700 p-5 rounded-2xl text-white shadow-lg shadow-emerald-600/20 flex items-center justify-between group transform transition-all active:scale-[0.98]"
                              >
                                  <div className="flex items-center gap-4">
                                      <div className="w-12 h-12 bg-white/20 backdrop-blur-sm rounded-full flex items-center justify-center shadow-inner">
                                          <BookOpen size={22} className="text-white" />
                                      </div>
                                      <div className="text-left">
                                          <p className="text-emerald-100 text-xs font-medium mb-1 flex items-center gap-1">
                                            <Clock size={10} /> Last Read
                                          </p>
                                          <p className="font-bold text-xl">{lastRead.englishName}</p>
                                          {/* Mini Progress for Last Read */}
                                          {progress[lastRead.number] && (
                                              <div className="mt-1 flex items-center gap-2">
                                                  <div className="h-1 bg-black/20 rounded-full w-24 overflow-hidden">
                                                      <div 
                                                        className="h-full bg-emerald-200" 
                                                        style={{ width: `${(progress[lastRead.number] / (surahs.find(s=>s.number===lastRead.number)?.numberOfAyahs || 1)) * 100}%` }}
                                                      ></div>
                                                  </div>
                                                  <span className="text-[10px] text-emerald-100">
                                                      Ayah {progress[lastRead.number]}
                                                  </span>
                                              </div>
                                          )}
                                      </div>
                                  </div>
                                  <div className="font-arabic text-3xl opacity-80 text-emerald-100">{lastRead.name.replace('سُورَةُ ', '')}</div>
                              </button>
                          </div>
                      )}

                      {/* Surah List */}
                      {searchTerm && <h2 className="text-xs font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wider mb-3 px-1">Search Results</h2>}

                      {filteredSurahs.map(surah => {
                          const surahProgress = progress[surah.number] || 0;
                          const percent = Math.round((surahProgress / surah.numberOfAyahs) * 100);

                          return (
                          <button 
                            key={surah.number}
                            onClick={() => selectSurah(surah)}
                            className="w-full bg-white dark:bg-slate-900 p-4 rounded-2xl border border-slate-100 dark:border-slate-800 hover:border-emerald-200 dark:hover:border-emerald-800 hover:shadow-sm transition-all flex items-center gap-4 text-left group"
                          >
                             <div className="w-10 h-10 bg-slate-50 dark:bg-slate-800 rounded-lg flex items-center justify-center font-bold text-slate-400 dark:text-slate-500 group-hover:text-emerald-600 dark:group-hover:text-emerald-400 group-hover:bg-emerald-50 dark:group-hover:bg-emerald-900/20 transition-colors relative overflow-hidden">
                                 <span className="relative z-10">{surah.number}</span>
                                 {percent === 100 && <div className="absolute inset-0 bg-emerald-100 dark:bg-emerald-900/40"></div>}
                             </div>
                             <div className="flex-1">
                                 <div className="flex justify-between items-center mb-1">
                                    <h3 className="font-bold text-slate-800 dark:text-slate-100">{surah.englishName}</h3>
                                    {surahProgress > 0 && (
                                        <span className="text-[10px] font-medium px-2 py-0.5 rounded-full bg-slate-100 dark:bg-slate-800 text-emerald-600 dark:text-emerald-400">
                                            {percent}%
                                        </span>
                                    )}
                                 </div>
                                 <p className="text-xs text-slate-500 dark:text-slate-400 mb-2">{surah.englishNameTranslation} • {surah.numberOfAyahs} Verses</p>

                                 {/* Progress Bar */}
                                 <div className="h-1 w-full bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden">
                                     <div 
                                        className={`h-full rounded-full transition-all duration-500 ${percent === 100 ? 'bg-emerald-500' : 'bg-emerald-500/60'}`} 
                                        style={{ width: `${percent}%` }}
                                     ></div>
                                 </div>
                             </div>
                             <div className="text-right pl-2">
                                 <span className="font-arabic text-xl text-slate-700 dark:text-slate-200">{surah.name.replace('سُورَةُ ', '')}</span>
                             </div>
                          </button>
                      )})}
                  </div>
              )}
           </div>
        </div>
     );
  }

  // Calculate detail progress
  const currentSurahProgress = progress[activeSurah.number] || 0;
  const detailPercent = (currentSurahProgress / activeSurah.numberOfAyahs) * 100;

  // Render Detail
  return (
      <div className="h-full flex flex-col animate-fade-in bg-white dark:bg-slate-950 relative">
          <audio ref={audioRef} className="hidden" preload="auto" />

          {/* Header */}
          <div className="sticky top-0 z-20 bg-white/95 dark:bg-slate-950/95 backdrop-blur-sm transition-colors border-b border-slate-100 dark:border-slate-800">
              <div className="px-4 py-4 flex items-center justify-between">
                  <button 
                    onClick={handleBack}
                    className="w-10 h-10 rounded-full hover:bg-slate-100 dark:hover:bg-slate-900 flex items-center justify-center text-slate-600 dark:text-slate-300 transition-colors"
                  >
                      <ArrowLeft size={22} />
                  </button>
                  <div className="text-center">
                      <h2 className="font-bold text-slate-800 dark:text-slate-100">{activeSurah.englishName}</h2>
                      <p className="text-xs text-slate-500 dark:text-slate-400">{activeSurah.englishNameTranslation}</p>
                  </div>
                  <button 
                    onClick={() => setShowReciterList(true)}
                    className={`w-10 h-10 rounded-full hover:bg-slate-100 dark:hover:bg-slate-900 flex items-center justify-center transition-colors ${isPlaying || audioUrls.length > 0 ? 'text-emerald-600 dark:text-emerald-400' : 'text-slate-600 dark:text-slate-300'}`}
                  >
                      <Headphones size={22} />
                  </button>
              </div>
              {/* Sticky Progress Bar */}
              <div className="h-1 w-full bg-slate-100 dark:bg-slate-800">
                  <div 
                      className="h-full bg-emerald-500 transition-all duration-300 ease-out"
                      style={{ width: `${detailPercent}%` }}
                  ></div>
              </div>
          </div>

          <div ref={topRef} className={`flex-1 overflow-y-auto pb-32 scroll-smooth ${showReciterList ? 'overflow-hidden' : ''}`}>
               {/* Bismillah Header - Show for all except At-Tawbah (9) */}
               {activeSurah.number !== 9 && !loadingSurah && (
                   <div className="py-8 flex justify-center text-slate-800 dark:text-slate-100 opacity-80">
                       <p className="font-arabic text-3xl">بِسْمِ ٱللَّٰهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ</p>
                   </div>
               )}

               {loadingSurah ? (
                   <div className="flex flex-col items-center justify-center py-32 space-y-4">
                       <Loader2 className="animate-spin text-emerald-600" size={32} />
                       <p className="text-sm text-slate-400">Loading verses...</p>
                   </div>
               ) : (
                   <div className="px-6 space-y-8 pb-10">
                       {ayahs.map((ayah, idx) => {
                           const isActive = currentAudioIndex === idx && isPlaying;
                           const isRead = ayah.number <= currentSurahProgress;

                           return (
                               <div 
                                   key={idx} 
                                   id={`ayah-${ayah.number}`}
                                   data-ayah-number={ayah.number}
                                   className={`ayah-item transition-all duration-500 ${isActive ? 'scale-[1.02]' : ''}`}
                               >
                                   {/* Arabic */}
                                   <div className={`w-full p-6 rounded-2xl mb-4 border transition-colors duration-300 ${isActive ? 'bg-emerald-50 dark:bg-emerald-900/20 border-emerald-200 dark:border-emerald-800' : 'bg-slate-50 dark:bg-slate-900/40 border-slate-100 dark:border-slate-800/50'}`}>
                                       <p className={`text-right font-arabic text-3xl leading-[2.5] ${isActive ? 'text-emerald-800 dark:text-emerald-100' : 'text-slate-800 dark:text-slate-100'}`} dir="rtl">
                                           {ayah.arabic} 
                                           <span className={`inline-flex items-center justify-center w-8 h-8 mx-2 text-sm border rounded-full font-sans number-symbol align-middle transition-colors duration-500 ${isActive ? 'bg-emerald-100 dark:bg-emerald-800 text-emerald-700 dark:text-emerald-200 border-emerald-300 dark:border-emerald-700' : isRead ? 'bg-emerald-500 text-white border-emerald-500' : 'bg-white dark:bg-slate-800 text-emerald-600 dark:text-emerald-400 border-emerald-500/50'}`}>
                                               {isRead && !isActive ? <Check size={12} strokeWidth={3} /> : ayah.number}
                                           </span>
                                       </p>
                                   </div>

                                   {/* Translation */}
                                   <div className="px-2">
                                       <p className={`leading-relaxed text-lg transition-colors ${isActive ? 'text-slate-800 dark:text-slate-200 font-medium' : 'text-slate-600 dark:text-slate-300'}`}>
                                           {ayah.translation}
                                       </p>
                                   </div>

                                   {idx < ayahs.length - 1 && (
                                       <div className="my-8 border-b border-slate-100 dark:border-slate-800/60 w-1/2 mx-auto"></div>
                                   )}
                               </div>
                           );
                       })}
                   </div>
               )}
          </div>

          {/* Audio Player Bar */}
          <div className="absolute bottom-0 left-0 right-0 bg-white dark:bg-slate-900 border-t border-slate-200 dark:border-slate-800 p-4 shadow-[0_-4px_10px_rgba(0,0,0,0.05)] z-30 transition-transform duration-300 flex items-center justify-between gap-4">
               <div className="flex flex-col min-w-0">
                   <span className="text-xs font-bold text-emerald-600 dark:text-emerald-400 uppercase tracking-wider">Now Playing</span>
                   <span className="text-sm font-semibold text-slate-800 dark:text-slate-100 truncate">{activeReciter.name}</span>
               </div>

               <div className="flex items-center gap-4">
                    <button 
                        onClick={() => setCurrentAudioIndex(prev => Math.max(0, prev - 1))}
                        className="text-slate-400 hover:text-slate-600 dark:hover:text-slate-200"
                        disabled={currentAudioIndex <= 0}
                    >
                        <SkipBack size={20} className="fill-current" />
                    </button>

                    <button 
                        onClick={togglePlay}
                        disabled={loadingAudio}
                        className="w-12 h-12 bg-emerald-600 hover:bg-emerald-700 text-white rounded-full flex items-center justify-center shadow-lg shadow-emerald-600/30 active:scale-95 transition-all"
                    >
                        {loadingAudio ? (
                            <Loader2 size={20} className="animate-spin" />
                        ) : isPlaying ? (
                            <Pause size={20} className="fill-current" />
                        ) : (
                            <Play size={20} className="fill-current ml-1" />
                        )}
                    </button>

                    <button 
                         onClick={() => setCurrentAudioIndex(prev => Math.min((audioUrls.length || ayahs.length) - 1, prev + 1))}
                         className="text-slate-400 hover:text-slate-600 dark:hover:text-slate-200"
                         disabled={currentAudioIndex >= (audioUrls.length || ayahs.length) - 1}
                    >
                        <SkipForward size={20} className="fill-current" />
                    </button>
               </div>
          </div>

          {/* Reciter Selection Modal */}
          {showReciterList && (
              <div className="absolute inset-0 z-40 bg-white dark:bg-slate-950 flex flex-col animate-fade-in">
                  <div className="p-4 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between bg-white dark:bg-slate-950">
                      <h3 className="font-bold text-lg text-slate-800 dark:text-slate-100">Select Reciter</h3>
                      <button onClick={() => setShowReciterList(false)} className="p-2 bg-slate-100 dark:bg-slate-900 rounded-full text-slate-500 hover:text-slate-800 dark:hover:text-slate-200">
                          <X size={20} />
                      </button>
                  </div>
                  <div className="flex-1 overflow-y-auto p-4 space-y-2">
                      {reciters.length === 0 && <div className="text-center p-10"><Loader2 className="animate-spin mx-auto text-emerald-500" /></div>}
                      {reciters.map((reciter) => (
                          <button
                              key={reciter.identifier}
                              onClick={() => handleReciterChange(reciter)}
                              className={`w-full p-4 rounded-xl flex items-center justify-between text-left transition-all ${activeReciter.identifier === reciter.identifier ? 'bg-emerald-50 dark:bg-emerald-900/20 border border-emerald-200 dark:border-emerald-800' : 'bg-white dark:bg-slate-900 border border-slate-100 dark:border-slate-800 hover:border-emerald-200 dark:hover:border-emerald-800'}`}
                          >
                              <div>
                                  <p className={`font-semibold ${activeReciter.identifier === reciter.identifier ? 'text-emerald-700 dark:text-emerald-400' : 'text-slate-700 dark:text-slate-200'}`}>
                                      {reciter.englishName}
                                  </p>
                                  <p className="text-xs text-slate-400 dark:text-slate-500">{reciter.name}</p>
                              </div>
                              {activeReciter.identifier === reciter.identifier && <Check size={18} className="text-emerald-600" />}
                          </button>
                      ))}
                  </div>
              </div>
          )}
      </div>
  );
};

export default QuranReader;

import React, { useState, useEffect } from 'react';
import { RotateCcw, Settings, Check, Volume2, VolumeX, Smartphone, Quote, X } from 'lucide-react';

interface TasbihCounterProps {
  onBack: () => void;
}

const DHIKR_QUOTES = [
  { text: "Verily, in the remembrance of Allah do hearts find rest.", source: "Surah Ar-Ra'd 13:28" },
  { text: "Remember Me; I will remember you.", source: "Surah Al-Baqarah 2:152" },
  { text: "And be patient. Indeed, Allah is with the patient.", source: "Surah Al-Anfal 8:46" },
  { text: "Two words are light on the tongue, weigh heavily in the scales, and are loved by the Most Merciful: SubhanAllah wa biHamdihi, SubhanAllah al-Adheem.", source: "Hadith (Bukhari)" },
  { text: "The most beloved deeds to Allah are those that are continuous, even if they are few.", source: "Hadith (Muslim)" },
  { text: "O you who have believed, seek help through patience and prayer.", source: "Surah Al-Baqarah 2:153" }
];

const TasbihCounter: React.FC<TasbihCounterProps> = ({ onBack }) => {
  const [count, setCount] = useState(0);
  const [target, setTarget] = useState<number>(33);
  const [loops, setLoops] = useState(0);
  const [vibrationEnabled, setVibrationEnabled] = useState(true);

  // Quote State
  const [currentQuote, setCurrentQuote] = useState<{text: string, source: string} | null>(null);
  const [showQuote, setShowQuote] = useState(true);

  useEffect(() => {
    const savedCount = localStorage.getItem('tasbih_count');
    const savedLoops = localStorage.getItem('tasbih_loops');
    const savedTarget = localStorage.getItem('tasbih_target');

    if (savedCount) setCount(parseInt(savedCount));
    if (savedLoops) setLoops(parseInt(savedLoops));
    if (savedTarget) setTarget(parseInt(savedTarget));

    // Select random quote
    setCurrentQuote(DHIKR_QUOTES[Math.floor(Math.random() * DHIKR_QUOTES.length)]);
  }, []);

  useEffect(() => {
    localStorage.setItem('tasbih_count', count.toString());
    localStorage.setItem('tasbih_loops', loops.toString());
    localStorage.setItem('tasbih_target', target.toString());
  }, [count, loops, target]);

  const handleTap = () => {
    if (vibrationEnabled && navigator.vibrate) {
      navigator.vibrate(15); // Short tick
    }

    const nextCount = count + 1;

    if (target !== 0 && nextCount > target) {
      // Loop complete
      if (vibrationEnabled && navigator.vibrate) {
        navigator.vibrate([50, 50, 50]); // Distinct pattern for completion
      }
      setCount(1);
      setLoops(l => l + 1);
    } else {
      setCount(nextCount);
    }
  };

  const handleReset = () => {
    if (confirm("Reset current counter?")) {
      setCount(0);
      setLoops(0);
      if (vibrationEnabled && navigator.vibrate) navigator.vibrate(50);
    }
  };

  const toggleTarget = () => {
    const targets = [33, 99, 100, 0]; // 0 is infinity
    const currentIndex = targets.indexOf(target);
    const nextTarget = targets[(currentIndex + 1) % targets.length];
    setTarget(nextTarget);
  };

  const progress = target === 0 ? 100 : (count / target) * 100;

  return (
    <div className="flex flex-col h-full bg-slate-50 dark:bg-slate-950 animate-fade-in relative overflow-hidden transition-colors duration-300">
      {/* Header */}
      <div className="flex items-center justify-between p-6 z-10">
        <button 
          onClick={onBack} 
          className="w-10 h-10 bg-white dark:bg-slate-900 rounded-full shadow-sm flex items-center justify-center text-slate-600 dark:text-slate-300 hover:text-emerald-600 dark:hover:text-emerald-400 transition-colors"
        >
          <RotateCcw size={20} />
        </button>
        <div className="flex flex-col items-center">
             <h1 className="text-xl font-bold text-slate-800 dark:text-slate-100">Tasbih</h1>
             <span className="text-xs text-slate-400 dark:text-slate-500 font-medium">Digital Dhikr</span>
        </div>
        <button 
          onClick={() => setVibrationEnabled(!vibrationEnabled)} 
          className={`w-10 h-10 rounded-full shadow-sm flex items-center justify-center transition-colors ${vibrationEnabled ? 'bg-emerald-50 dark:bg-emerald-900/20 text-emerald-600 dark:text-emerald-400' : 'bg-white dark:bg-slate-900 text-slate-400 dark:text-slate-500'}`}
        >
          {vibrationEnabled ? <Volume2 size={20} /> : <VolumeX size={20} />}
        </button>
      </div>

      <div className="flex-1 flex flex-col items-center justify-center px-6 pb-24 relative w-full max-w-md mx-auto">

        {/* Quote Card */}
        {showQuote && currentQuote && (
            <div className="w-full mb-6 relative group animate-fade-in-up">
                <div className="bg-emerald-50 dark:bg-emerald-900/20 p-5 rounded-2xl border border-emerald-100 dark:border-emerald-900/50 shadow-sm relative overflow-hidden">
                    <div className="absolute top-0 right-0 w-24 h-24 bg-emerald-200 dark:bg-emerald-800 rounded-full blur-3xl opacity-20 -mr-10 -mt-10 pointer-events-none"></div>

                    <button 
                        onClick={() => setShowQuote(false)}
                        className="absolute top-3 right-3 text-slate-400 hover:text-emerald-600 dark:hover:text-emerald-400 transition-colors bg-white/50 dark:bg-black/10 rounded-full p-1"
                    >
                        <X size={14} />
                    </button>

                    <div className="flex gap-4">
                        <div className="flex-shrink-0 mt-1">
                            <Quote size={20} className="text-emerald-500 fill-emerald-500/20" />
                        </div>
                        <div className="pr-4">
                            <p className="text-sm text-slate-700 dark:text-slate-200 font-medium leading-relaxed italic">"{currentQuote.text}"</p>
                            <p className="text-xs text-emerald-600 dark:text-emerald-400 mt-3 font-bold uppercase tracking-wide flex items-center gap-2">
                                <span className="w-4 h-[1px] bg-emerald-400"></span>
                                {currentQuote.source}
                            </p>
                        </div>
                    </div>
                </div>
            </div>
        )}

        {/* Info Display */}
        <div className="mb-8 text-center space-y-1">
            <p className="text-slate-400 dark:text-slate-500 text-xs font-medium uppercase tracking-wider">Total Loops: {loops}</p>
            <button 
                onClick={toggleTarget}
                className="bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 px-3 py-1 rounded-full text-xs font-semibold text-slate-600 dark:text-slate-300 hover:border-emerald-500 dark:hover:border-emerald-500 transition-colors flex items-center gap-2 mx-auto"
            >
                Target: {target === 0 ? '∞' : target}
                <Settings size={12} />
            </button>
        </div>

        {/* Main Counter Button */}
        <button 
            onClick={handleTap}
            className="relative w-64 h-64 rounded-full bg-white dark:bg-slate-900 shadow-[0_10px_40px_-10px_rgba(0,0,0,0.1)] dark:shadow-[0_10px_40px_-10px_rgba(0,0,0,0.5)] flex items-center justify-center group active:scale-95 transition-all duration-100 touch-manipulation tap-highlight-transparent"
            style={{ WebkitTapHighlightColor: 'transparent' }}
        >
            {/* Progress Ring Background */}
            <svg className="absolute inset-0 w-full h-full -rotate-90 pointer-events-none" viewBox="0 0 100 100">
                <circle 
                    cx="50" cy="50" r="46" 
                    fill="none" 
                    className="stroke-slate-100 dark:stroke-slate-800 transition-colors duration-300"
                    strokeWidth="4" 
                />
                <circle 
                    cx="50" cy="50" r="46" 
                    fill="none" 
                    stroke="#10b981" 
                    strokeWidth="4" 
                    strokeDasharray="289" // 2 * pi * 46
                    strokeDashoffset={289 - (289 * progress) / 100}
                    strokeLinecap="round"
                    className="transition-all duration-300 ease-out"
                />
            </svg>

            {/* Inner Content */}
            <div className="flex flex-col items-center z-10">
                <span className="text-7xl font-bold text-slate-800 dark:text-slate-100 font-mono tracking-tighter tabular-nums select-none">
                    {count}
                </span>
