const adjustTime = (time: string, minutes: number): string => {
  const cleanTime = time.split(' ')[0];
  const [h, m] = cleanTime.split(':').map(Number);

  const date = new Date();
  date.setHours(h);
  date.setMinutes(m + minutes);

  return `${date.getHours().toString().padStart(2, '0')}:${date.getMinutes().toString().padStart(2, '0')}`;
};

export const getPrayerTimes = async (
  lat: number, 
  lng: number, 
  method: number = 2, 
  offset: number = 0
): Promise<{ timings: PrayerTimes, date: HijriDate } | null> => {
  try {
    const date = new Date();
    // Format: DD-MM-YYYY (Month is 0-indexed in JS)
    const dateStr = `${date.getDate()}-${date.getMonth() + 1}-${date.getFullYear()}`;

    // Cache keys
    // Round to 2 decimal places (approx 1.1km) to group nearby requests and improve cache hits
    const latKey = lat.toFixed(2);
    const lngKey = lng.toFixed(2);
    const cacheKey = `noor_prayer_${dateStr}_${latKey}_${lngKey}_${method}`;
    const fallbackKey = `noor_prayer_fallback`;

    let data = null;

    // 1. Try exact cache first (Fastest)
    try {
      const cached = localStorage.getItem(cacheKey);
      if (cached) {
        data = JSON.parse(cached);
      }
    } catch (e) {
      console.error("Error reading cache", e);
    }

    // 2. Fetch from API if not in cache
    if (!data) {
      try {
        const response = await fetch(`https://api.aladhan.com/v1/timings/${dateStr}?latitude=${lat}&longitude=${lng}&method=${method}`);
        const json = await response.json();

        if (json.code === 200 && json.data) {
          data = json.data;

          // Save to exact cache
          localStorage.setItem(cacheKey, JSON.stringify(data));

          // Save to fallback cache (Last known good data)
          localStorage.setItem(fallbackKey, JSON.stringify({
            date: dateStr,
            data: data,
            timestamp: Date.now()
          }));
        }
      } catch (networkError) {
        console.warn("Network error, attempting fallback", networkError);
      }
    }

    // 3. Fallback to last known good data if fetch failed
    if (!data) {
      try {
        const fallback = localStorage.getItem(fallbackKey);
        if (fallback) {
          const parsed = JSON.parse(fallback);
          // Only use fallback if it matches today's date
          // This prevents showing wrong prayer times from yesterday
          if (parsed.date === dateStr) {
             console.log("Using offline fallback data");
             data = parsed.data;
          }
        }
      } catch (e) {
        console.error("Error reading fallback", e);
      }
    }

    if (data && data.timings) {
      let timings = data.timings;

      // Apply offset if any
      if (offset !== 0) {
        const adjusted: any = {};
        for (const [key, val] of Object.entries(timings)) {
           // Only adjust time strings (format HH:MM)
           if (typeof val === 'string' && val.includes(':')) {
              adjusted[key] = adjustTime(val as string, offset);
           } else {
              adjusted[key] = val;
           }
        }
        timings = adjusted;
      }

      return {
        timings: timings,
        date: data.data.date.hijri
      };
    }
  } catch (error) {
    console.error("Error fetching prayer times:", error);
  }
  return null;
};

