import { Search, ArrowLeft, Loader2, AlertCircle, BookOpen, Clock, Play, Pause, SkipForward, SkipBack, X, Headphones, Check, CheckCircle2 } from 'lucide-react';

interface Surah {
  number: number;
  name: string;
  englishName: string;
  englishNameTranslation: string;
