export default App;

import React, { useState, useEffect, useRef } from 'react';
import { Book, ChevronRight, ArrowLeft, Search, Loader2, BookOpen, ScrollText } from 'lucide-react';

interface BookDef {
  id: string;
  name: string;
  arabicName: string;
  author: string;
}

interface Section {
  number: string;
  title: string;
}

interface Hadith {
  hadithnumber: number;
  arabicnumber: number;
  text: string;
  grades?: { grade: string; source: string }[];
  reference?: { book: number; hadith: number };
}

const BOOKS: BookDef[] = [
  { id: 'bukhari', name: 'Sahih al-Bukhari', arabicName: 'صحيح البخاري', author: 'Imam Bukhari' },
  { id: 'muslim', name: 'Sahih Muslim', arabicName: 'صحيح مسلم', author: 'Imam Muslim' },
  { id: 'nasai', name: 'Sunan an-Nasa\'i', arabicName: 'سنن النسائي', author: 'Imam An-Nasa\'i' },
  { id: 'abudawud', name: 'Sunan Abu Dawud', arabicName: 'سنن أبي داود', author: 'Imam Abu Dawud' },
  { id: 'tirmidhi', name: 'Jami\' at-Tirmidhi', arabicName: 'جامع الترمذي', author: 'Imam At-Tirmidhi' },
  { id: 'ibnmajah', name: 'Sunan Ibn Majah', arabicName: 'سنن ابن ماجه', author: 'Imam Ibn Majah' },
  { id: 'malik', name: 'Muwatta Malik', arabicName: 'موطأ مالك', author: 'Imam Malik' },
  { id: 'ahmed', name: 'Musnad Ahmad', arabicName: 'مسند أحمد', author: 'Imam Ahmad' },
];

const HadithCatalog: React.FC = () => {
  const [view, setView] = useState<'books' | 'sections' | 'hadiths'>('books');
  const [selectedBook, setSelectedBook] = useState<BookDef | null>(null);
  const [selectedSection, setSelectedSection] = useState<Section | null>(null);

  // Data States
  const [sections, setSections] = useState<Section[]>([]);
  const [hadiths, setHadiths] = useState<{ en: Hadith, ar?: Hadith }[]>([]);

  const [loading, setLoading] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  const scrollRef = useRef<HTMLDivElement>(null);

  // Scroll to top on view change
  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = 0;
  }, [view, selectedBook, selectedSection]);

  const fetchSections = async (bookId: string) => {
      setLoading(true);
      try {
          // Fetch English sections metadata
          const res = await fetch(`https://cdn.jsdelivr.net/gh/fawazahmed0/hadith-api@1/editions/eng-${bookId}/sections.json`);
          if (!res.ok) throw new Error("Failed to fetch sections");

          const data = await res.json();
          // The API returns an object { "1": "Name", "2": "Name" }, convert to array
          const sectionList: Section[] = Object.entries(data)
              .map(([key, val]) => ({ number: key, title: val as string }))
              .filter(s => s.title && s.number !== '0') // Filter empty
              .sort((a, b) => parseInt(a.number) - parseInt(b.number));

          setSections(sectionList);
          setView('sections');
      } catch (e) {
          console.error(e);
          alert("Could not load chapters for this book.");
      } finally {
          setLoading(false);
      }
  };

  const fetchHadiths = async (bookId: string, sectionNumber: string) => {
      setLoading(true);
      try {
          // Fetch English and Arabic in parallel
          const [resEn, resAr] = await Promise.all([
             fetch(`https://cdn.jsdelivr.net/gh/fawazahmed0/hadith-api@1/editions/eng-${bookId}/sections/${sectionNumber}.json`),
             fetch(`https://cdn.jsdelivr.net/gh/fawazahmed0/hadith-api@1/editions/ara-${bookId}/sections/${sectionNumber}.json`)
          ]);

          let enData: { hadiths: Hadith[] } = { hadiths: [] };
          let arData: { hadiths: Hadith[] } = { hadiths: [] };

          if (resEn.ok) enData = await resEn.json();
          if (resAr.ok) arData = await resAr.json();

          // Merge by hadith number
          const merged = enData.hadiths.map(hEn => {
              const hAr = arData.hadiths.find(h => h.hadithnumber === hEn.hadithnumber);
              return { en: hEn, ar: hAr };
          });

          setHadiths(merged);
          setView('hadiths');
      } catch (e) {
          console.error(e);
          alert("Could not load hadiths.");
      } finally {
          setLoading(false);
      }
  };

  const handleBookSelect = (book: BookDef) => {
      setSelectedBook(book);
      fetchSections(book.id);
  };

  const handleSectionSelect = (section: Section) => {
      if (!selectedBook) return;
      setSelectedSection(section);
      fetchHadiths(selectedBook.id, section.number);
  };

  const handleBack = () => {
      if (view === 'hadiths') {
          setView('sections');
          setHadiths([]);
          setSelectedSection(null);
      } else if (view === 'sections') {
          setView('books');
          setSections([]);
          setSelectedBook(null);
      }
  };

  const filteredSections = sections.filter(s => s.title.toLowerCase().includes(searchTerm.toLowerCase()));
  const filteredHadiths = hadiths.filter(h => h.en.text.toLowerCase().includes(searchTerm.toLowerCase()));

  // -- RENDERERS --

  const renderBooks = () => (
      <div className="grid grid-cols-1 gap-4 px-6 pb-24">
          <div className="bg-emerald-50 dark:bg-emerald-900/20 p-6 rounded-3xl mb-4 border border-emerald-100 dark:border-emerald-900/50 text-center">
              <ScrollText size={32} className="mx-auto text-emerald-600 dark:text-emerald-400 mb-2" />
              <h2 className="text-xl font-bold text-slate-800 dark:text-slate-100">Hadith Collections</h2>
              <p className="text-sm text-slate-500 dark:text-slate-400">Authentic narrations from the Sunnah</p>
          </div>

          {BOOKS.map(book => (
              <button
                  key={book.id}
                  onClick={() => handleBookSelect(book)}
                  className="bg-white dark:bg-slate-900 p-5 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-800 hover:border-emerald-200 dark:hover:border-emerald-800 transition-all text-left flex items-center justify-between group"
              >
                  <div className="flex items-center gap-4">
                      <div className="w-12 h-12 bg-slate-50 dark:bg-slate-800 rounded-full flex items-center justify-center text-slate-400 dark:text-slate-500 group-hover:bg-emerald-50 dark:group-hover:bg-emerald-900/30 group-hover:text-emerald-600 dark:group-hover:text-emerald-400 transition-colors">
                          <Book size={20} />
                      </div>
                      <div>
                          <h3 className="font-bold text-slate-800 dark:text-slate-100">{book.name}</h3>
                          <p className="text-xs text-slate-500 dark:text-slate-400">{book.author}</p>
                      </div>
                  </div>
                  <div className="text-right">
                       <span className="block font-arabic text-lg text-emerald-600 dark:text-emerald-400">{book.arabicName}</span>
                  </div>
              </button>
          ))}
      </div>
  );

  const renderSections = () => (
      <div className="px-6 pb-24">
          <div className="sticky top-0 bg-slate-50 dark:bg-slate-950 pt-2 pb-4 z-10">
             <div className="relative">
                 <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                 <input 
                   type="text" 
                   placeholder={`Search chapters in ${selectedBook?.name}...`}
                   className="w-full bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-xl py-3 pl-10 pr-4 text-slate-800 dark:text-slate-100 placeholder:text-slate-400 focus:ring-2 focus:ring-emerald-500/50 outline-none transition-all"
                   value={searchTerm}
                   onChange={(e) => setSearchTerm(e.target.value)}
                 />
              </div>
          </div>

          <div className="space-y-3">
              {filteredSections.map(section => (
                  <button
                      key={section.number}
                      onClick={() => handleSectionSelect(section)}
                      className="w-full bg-white dark:bg-slate-900 p-4 rounded-xl border border-slate-100 dark:border-slate-800 hover:border-emerald-200 dark:hover:border-emerald-800 transition-all text-left flex items-center gap-4 group"
                  >
                      <span className="w-8 h-8 rounded-lg bg-slate-100 dark:bg-slate-800 flex items-center justify-center text-xs font-bold text-slate-500 dark:text-slate-400 group-hover:text-emerald-600 dark:group-hover:text-emerald-400">
                          {section.number}
                      </span>
                      <div className="flex-1">
                          <h3 className="font-medium text-slate-800 dark:text-slate-100">{section.title}</h3>
                      </div>
                      <ChevronRight size={18} className="text-slate-300 dark:text-slate-600 group-hover:text-emerald-500" />
                  </button>
              ))}
              {filteredSections.length === 0 && (
                  <div className="text-center py-10 text-slate-400">No chapters found.</div>
              )}
          </div>
      </div>
  );

  const renderHadiths = () => (
      <div className="px-6 pb-24">
          <div className="sticky top-0 bg-slate-50 dark:bg-slate-950 pt-2 pb-4 z-10">
             <div className="relative">
                 <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                 <input 
                   type="text" 
                   placeholder="Search in this chapter..."
                   className="w-full bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-xl py-3 pl-10 pr-4 text-slate-800 dark:text-slate-100 placeholder:text-slate-400 focus:ring-2 focus:ring-emerald-500/50 outline-none transition-all"
                   value={searchTerm}
                   onChange={(e) => setSearchTerm(e.target.value)}
                 />
              </div>
          </div>

          <div className="space-y-6">
              {filteredHadiths.map((item, idx) => (
                  <div key={idx} className="bg-white dark:bg-slate-900 rounded-2xl p-6 shadow-sm border border-slate-100 dark:border-slate-800">
                      <div className="flex justify-between items-start mb-4 border-b border-slate-50 dark:border-slate-800 pb-3">
                          <span className="text-xs font-bold bg-emerald-50 dark:bg-emerald-900/30 text-emerald-600 dark:text-emerald-400 px-2 py-1 rounded-md">
                              Hadith {item.en.hadithnumber}
                          </span>
                          {item.en.grades && item.en.grades.length > 0 && (
                              <span className={`text-[10px] uppercase font-bold px-2 py-1 rounded-full ${item.en.grades[0].grade.toLowerCase().includes('sahih') ? 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400' : 'bg-slate-100 text-slate-600 dark:bg-slate-800 dark:text-slate-400'}`}>
                                  {item.en.grades[0].grade}
                              </span>
                          )}
                      </div>

                      {item.ar && (
                          <p className="font-arabic text-xl text-right leading-loose text-slate-800 dark:text-slate-100 mb-6" dir="rtl">
                              {item.ar.text}
                          </p>
                      )}

                      <p className="text-slate-600 dark:text-slate-300 leading-relaxed text-sm">
                          {item.en.text}
                      </p>
                  </div>
              ))}
              {filteredHadiths.length === 0 && (
                  <div className="text-center py-10 text-slate-400">No hadiths found.</div>
              )}
          </div>
      </div>
  );

  return (
    <div className="h-full flex flex-col relative bg-slate-50 dark:bg-slate-950 animate-fade-in">
        {/* Header */}
        <div className="bg-white/95 dark:bg-slate-950/95 backdrop-blur-sm sticky top-0 z-20 border-b border-slate-100 dark:border-slate-800 px-4 py-4 flex items-center gap-4">
            {view !== 'books' && (
                <button 
                  onClick={handleBack}
                  className="w-10 h-10 rounded-full hover:bg-slate-100 dark:hover:bg-slate-900 flex items-center justify-center text-slate-600 dark:text-slate-300 transition-colors"
                >
                    <ArrowLeft size={22} />
                </button>
            )}
            <div className="flex-1">
                <h1 className="font-bold text-lg text-slate-800 dark:text-slate-100 truncate">
                    {view === 'books' ? 'Hadith Catalog' : view === 'sections' ? selectedBook?.name : selectedSection?.title}
                </h1>
                {view !== 'books' && (
                    <p className="text-xs text-slate-500 dark:text-slate-400 truncate">
                        {view === 'sections' ? selectedBook?.author : selectedBook?.name}
                    </p>
                )}
            </div>
        </div>

        {/* Content */}
        <div ref={scrollRef} className="flex-1 overflow-y-auto pt-4 scroll-smooth">
            {loading ? (
                <div className="flex flex-col items-center justify-center py-20">
                    <Loader2 className="animate-spin text-emerald-600 mb-2" size={32} />
                    <p className="text-sm text-slate-400">Loading...</p>
                </div>
            ) : (
                <>
                    {view === 'books' && renderBooks()}
                    {view === 'sections' && renderSections()}
                    {view === 'hadiths' && renderHadiths()}
                </>
            )}
        </div>
    </div>
  );
};

